var QBANK = {};
QBANK["AR"] = [{"q":"A store sells pencils in boxes of 12. If a teacher buys 8 boxes, how many pencils does she have in total?","c":["96","84","104","120"],"a":0,"e":"12 pencils per box times 8 boxes = 96 pencils. The answer is 96.","d":1},{"q":"A car travels 240 miles in 4 hours. What is its average speed in miles per hour?","c":["48 mph","56 mph","60 mph","64 mph"],"a":2,"e":"Average speed = distance / time = 240 / 4 = 60 mph.","d":1},{"q":"A shirt originally priced at $40 is on sale for 25% off. What is the sale price?","c":["$10","$30","$35","$32"],"a":1,"e":"25% of $40 = $10 discount. $40 - $10 = $30 sale price.","d":2},{"q":"If 3/4 of a class of 28 students passed a test, how many students passed?","c":["7","18","24","21"],"a":3,"e":"3/4 of 28 = (28 / 4) x 3 = 7 x 3 = 21 students passed.","d":2},{"q":"A recipe calls for 2 1/2 cups of flour. If you make a triple batch, how many cups of flour do you need?","c":["5 cups","6 cups","7 1/2 cups","8 cups"],"a":2,"e":"2.5 cups x 3 = 7.5 cups, which is 7 1/2 cups.","d":2},{"q":"What is 15% of 80?","c":["8","12","16","15"],"a":1,"e":"15% = 0.15. 0.15 x 80 = 12.","d":2},{"q":"A worker earns $18 per hour and works 35 hours in a week. How much does she earn that week?","c":["$540","$630","$700","$590"],"a":1,"e":"$18 x 35 = $630 for the week.","d":1},{"q":"Two numbers have a sum of 50. If one number is 18, what is the other?","c":["68","32","22","42"],"a":1,"e":"50 - 18 = 32. The other number is 32.","d":1},{"q":"A rectangular room is 12 feet long and 9 feet wide. What is its area?","c":["21 sq ft","42 sq ft","108 sq ft","96 sq ft"],"a":2,"e":"Area = length x width = 12 x 9 = 108 square feet.","d":1},{"q":"A water tank holds 60 gallons and is 3/5 full. How many gallons of water are in it?","c":["20 gallons","36 gallons","45 gallons","40 gallons"],"a":1,"e":"3/5 of 60 = (60 / 5) x 3 = 12 x 3 = 36 gallons.","d":2},{"q":"If a map scale is 1 inch = 25 miles, how many miles do 4 inches represent?","c":["100 miles","75 miles","29 miles","125 miles"],"a":0,"e":"4 inches x 25 miles per inch = 100 miles.","d":1},{"q":"The average of three numbers is 20. If two of the numbers are 15 and 22, what is the third?","c":["18","25","23","20"],"a":2,"e":"Sum = 20 x 3 = 60. 60 - 15 - 22 = 23. The third number is 23.","d":2},{"q":"A jacket costs $80. The sales tax is 7%. What is the total cost including tax?","c":["$85.60","$87.00","$80.70","$85.50"],"a":0,"e":"Tax = 7% of $80 = 0.07 x 80 = $5.60. Total = $80 + $5.60 = $85.60.","d":3},{"q":"A train leaves at 9:00 AM and arrives at 1:30 PM. How long was the trip?","c":["3 hours 30 minutes","4 hours","4 hours 30 minutes","5 hours"],"a":2,"e":"From 9:00 AM to 1:30 PM is 4 hours and 30 minutes.","d":1},{"q":"If 5 apples cost $2.00, how much do 12 apples cost at the same rate?","c":["$4.80","$5.00","$4.40","$6.00"],"a":0,"e":"Each apple costs $2.00 / 5 = $0.40. 12 x $0.40 = $4.80.","d":3},{"q":"What is the perimeter of a square with a side length of 7 cm?","c":["14 cm","21 cm","28 cm","49 cm"],"a":2,"e":"Perimeter of a square = 4 x side = 4 x 7 = 28 cm.","d":1},{"q":"A number increased by 12 equals 30. What is the number?","c":["42","18","22","16"],"a":1,"e":"Let the number be n. n + 12 = 30, so n = 30 - 12 = 18.","d":1},{"q":"A car uses 1 gallon of gas to travel 28 miles. How many gallons are needed to travel 196 miles?","c":["6 gallons","8 gallons","7 gallons","5 gallons"],"a":2,"e":"196 / 28 = 7 gallons needed.","d":2},{"q":"What is 0.25 written as a fraction in lowest terms?","c":["1/2","1/3","2/5","1/4"],"a":3,"e":"0.25 = 25/100 = 1/4 in lowest terms.","d":1},{"q":"A box of cereal weighs 18 ounces. How many ounces do 6 boxes weigh?","c":["108 ounces","96 ounces","120 ounces","114 ounces"],"a":0,"e":"18 x 6 = 108 ounces.","d":1},{"q":"If you save $25 each week, how much will you save in 8 weeks?","c":["$175","$200","$225","$250"],"a":1,"e":"$25 x 8 = $200.","d":1},{"q":"A pizza is cut into 8 equal slices. If 3 slices are eaten, what fraction of the pizza remains?","c":["3/8","1/2","5/8","2/3"],"a":2,"e":"8 - 3 = 5 slices remain, which is 5/8 of the pizza.","d":1},{"q":"A 5-pound bag of sugar costs $4.50. What is the cost per pound?","c":["$0.90","$1.00","$0.85","$0.80"],"a":0,"e":"$4.50 / 5 = $0.90 per pound.","d":1},{"q":"What is 3/5 of 45?","c":["15","25","27","30"],"a":2,"e":"3/5 of 45 = (45 / 5) x 3 = 9 x 3 = 27.","d":2},{"q":"A rectangle has a perimeter of 30 inches. If its width is 6 inches, what is its length?","c":["9 inches","12 inches","24 inches","15 inches"],"a":0,"e":"Perimeter = 2(L + W). 30 = 2(L + 6), so L + 6 = 15, L = 9 inches.","d":3},{"q":"A store marks up a $20 item by 30%. What is the new price?","c":["$23","$50","$26","$24"],"a":2,"e":"30% of $20 = $6. $20 + $6 = $26.","d":3},{"q":"If a runner completes a 10-kilometer race in 50 minutes, what is the average time per kilometer?","c":["6 minutes","4 minutes","10 minutes","5 minutes"],"a":3,"e":"50 minutes / 10 km = 5 minutes per kilometer.","d":2},{"q":"A class has 15 boys and 10 girls. What is the ratio of boys to girls in simplest form?","c":["2:3","5:2","3:2","15:10"],"a":2,"e":"15:10 simplifies by dividing both by 5 to get 3:2.","d":2},{"q":"What is the sum of 3/8 and 1/4?","c":["4/12","5/8","1/2","3/8"],"a":1,"e":"1/4 = 2/8. 3/8 + 2/8 = 5/8.","d":1},{"q":"A worker completes a job in 6 hours. Working at the same rate, how long to complete 4 such jobs?","c":["10 hours","18 hours","24 hours","20 hours"],"a":2,"e":"6 hours x 4 jobs = 24 hours.","d":1},{"q":"You deposit $500 in an account that earns 4% simple interest per year. How much interest do you earn in one year?","c":["$20","$40","$25","$54"],"a":0,"e":"Simple interest = $500 x 0.04 x 1 = $20.","d":1},{"q":"A bag contains 4 red marbles and 6 blue marbles. If one is drawn at random, what is the probability it is red?","c":["6/10","4/6","2/5","1/4"],"a":2,"e":"P(red) = 4 / (4 + 6) = 4/10 = 2/5.","d":2},{"q":"A car's gas tank holds 16 gallons. If gas costs $3.50 per gallon, how much to fill an empty tank?","c":["$48.00","$56.00","$52.00","$60.00"],"a":1,"e":"16 x $3.50 = $56.00.","d":2},{"q":"What is 120 divided by 8?","c":["12","14","16","15"],"a":3,"e":"120 / 8 = 15.","d":1},{"q":"A triangle has a base of 10 cm and a height of 6 cm. What is its area?","c":["60 sq cm","16 sq cm","30 sq cm","36 sq cm"],"a":2,"e":"Area of a triangle = (1/2) x base x height = (1/2) x 10 x 6 = 30 sq cm.","d":2},{"q":"If 40% of a number is 32, what is the number?","c":["80","12.8","72","128"],"a":0,"e":"0.40 x n = 32, so n = 32 / 0.40 = 80.","d":2},{"q":"A cube has edges of 3 inches. What is its volume?","c":["9 cubic inches","27 cubic inches","18 cubic inches","12 cubic inches"],"a":1,"e":"Volume of a cube = edge cubed = 3 x 3 x 3 = 27 cubic inches.","d":2},{"q":"$1,000 is invested at 5% interest compounded annually. What is the balance after 2 years?","c":["$1,100.00","$1,102.50","$1,050.00","$1,105.00"],"a":1,"e":"Year 1: $1,000 x 1.05 = $1,050. Year 2: $1,050 x 1.05 = $1,102.50.","d":3},{"q":"A recipe serves 4 people and uses 6 eggs. How many eggs are needed to serve 10 people?","c":["12 eggs","16 eggs","15 eggs","18 eggs"],"a":2,"e":"Eggs per person = 6 / 4 = 1.5. For 10 people: 1.5 x 10 = 15 eggs.","d":2},{"q":"How many feet are in 3 1/2 yards?","c":["7 feet","9 feet","10 1/2 feet","42 feet"],"a":2,"e":"1 yard = 3 feet. 3.5 x 3 = 10.5 feet, which is 10 1/2 feet.","d":2},{"q":"What is 9 plus 6?","c":["13","15","16","14"],"a":1,"e":"9 + 6 = 15.","d":1},{"q":"A dozen eggs costs $3.00. What is the cost of one egg?","c":["$0.20","$0.30","$0.25","$0.36"],"a":2,"e":"$3.00 / 12 = $0.25 per egg.","d":2},{"q":"What is double the number 17?","c":["27","32","34","37"],"a":2,"e":"2 x 17 = 34.","d":1},{"q":"A bus travels at 45 miles per hour. How far does it travel in 3 hours?","c":["135 miles","120 miles","150 miles","90 miles"],"a":0,"e":"Distance = speed x time = 45 x 3 = 135 miles.","d":2},{"q":"A movie starts at 7:15 PM and lasts 1 hour and 50 minutes. What time does it end?","c":["8:55 PM","9:05 PM","9:00 PM","8:50 PM"],"a":1,"e":"7:15 PM plus 1 hour = 8:15 PM. 8:15 PM plus 50 minutes = 9:05 PM.","d":2},{"q":"A test has 50 questions and a student answers 44 correctly. What percent did the student get correct?","c":["86%","90%","88%","82%"],"a":2,"e":"44 / 50 = 0.88 = 88%.","d":2},{"q":"Two trains start 350 miles apart and travel toward each other, one at 60 mph and the other at 80 mph. How long until they meet?","c":["2 hours","2.5 hours","3 hours","3.5 hours"],"a":1,"e":"Closing speed = 60 + 80 = 140 mph. Time = 350 / 140 = 2.5 hours.","d":3},{"q":"A solution is made by mixing 3 liters of a 20% acid solution with 2 liters of a 45% acid solution. What is the acid percentage of the mixture?","c":["32.5%","30%","35%","28%"],"a":1,"e":"Acid = 3 x 0.20 + 2 x 0.45 = 0.6 + 0.9 = 1.5 liters in 5 liters total. 1.5 / 5 = 0.30 = 30%.","d":3},{"q":"Pipe A fills a tank in 4 hours and pipe B fills it in 6 hours. Working together, how long to fill the tank?","c":["2.4 hours","2.5 hours","5 hours","3 hours"],"a":0,"e":"Combined rate = 1/4 + 1/6 = 3/12 + 2/12 = 5/12 tank per hour. Time = 12/5 = 2.4 hours.","d":3},{"q":"A jacket priced at $120 is discounted 25%, then an additional 10% is taken off the reduced price. What is the final price?","c":["$78","$81","$84","$77"],"a":1,"e":"After 25% off: $120 x 0.75 = $90. After 10% off: $90 x 0.90 = $81.","d":3},{"q":"A population of bacteria doubles every hour. If there are 200 bacteria now, how many will there be in 3 hours?","c":["600","1200","1600","800"],"a":2,"e":"Double each hour: 200 to 400 to 800 to 1600. After 3 hours there are 1600.","d":3},{"q":"A car averages 25 miles per gallon. If gas costs $4.20 per gallon, what is the fuel cost for a 300-mile trip?","c":["$50.40","$48.00","$52.50","$46.20"],"a":0,"e":"Gallons used = 300 / 25 = 12. Cost = 12 x $4.20 = $50.40.","d":3},{"q":"A circular garden has a radius of 7 feet. Using pi = 22/7, what is its area?","c":["44 sq ft","154 sq ft","308 sq ft","49 sq ft"],"a":1,"e":"Area = pi x r squared = (22/7) x 7 x 7 = 22 x 7 = 154 square feet.","d":3},{"q":"What is 7/10 expressed as a decimal?","c":["0.07","0.7","7.0","0.17"],"a":1,"e":"7/10 = 0.7.","d":1},{"q":"A worker is paid time-and-a-half for overtime. Her regular rate is $16 per hour. What does she earn for 5 overtime hours?","c":["$80","$120","$100","$112"],"a":1,"e":"Overtime rate = 1.5 x $16 = $24 per hour. 5 x $24 = $120.","d":3},{"q":"A rectangular field is 40 meters long and 30 meters wide. A fence is built around it. How many meters of fencing are needed?","c":["120 meters","140 meters","1200 meters","70 meters"],"a":1,"e":"Perimeter = 2(40 + 30) = 2 x 70 = 140 meters.","d":2},{"q":"In a class, 60% of 30 students are girls. How many boys are there?","c":["18","10","15","12"],"a":3,"e":"Girls = 0.60 x 30 = 18. Boys = 30 - 18 = 12.","d":3},{"q":"A store buys a TV for $250 and sells it for $325. What is the percent markup?","c":["25%","30%","35%","23%"],"a":1,"e":"Markup = $325 - $250 = $75. Percent = 75 / 250 = 0.30 = 30%.","d":3},{"q":"A swimming pool 20 feet long, 10 feet wide, and 5 feet deep is filled with water. How many cubic feet of water does it hold?","c":["1000 cubic feet","350 cubic feet","100 cubic feet","700 cubic feet"],"a":0,"e":"Volume = length x width x depth = 20 x 10 x 5 = 1000 cubic feet.","d":2},{"q":"A loan of $2,000 is taken at 6% simple interest for 3 years. What is the total amount to repay?","c":["$2,360","$2,180","$2,300","$2,400"],"a":0,"e":"Interest = $2,000 x 0.06 x 3 = $360. Total = $2,000 + $360 = $2,360.","d":3}];
QBANK["MK"] = [{"q":"What is 7 + 3 * 4 - 2?","c":["38","17","20","11"],"a":1,"e":"Order of operations: multiply first, 3*4=12. Then 7+12-2 = 17.","d":1},{"q":"Simplify: (8 - 3)^2 + 6 / 2","c":["28","22","13","16"],"a":0,"e":"Parentheses: 8-3=5, square it: 25. Then 6/2=3. 25+3 = 28.","d":2},{"q":"What is the value of 3^4?","c":["12","64","27","81"],"a":3,"e":"3^4 = 3*3*3*3 = 9*9 = 81.","d":1},{"q":"Simplify: x^5 * x^3","c":["x^8","x^15","x^2","2x^8"],"a":0,"e":"When multiplying like bases, add exponents: 5+3=8, so x^8.","d":2},{"q":"Simplify: (x^4)^3","c":["x^7","x^12","x^64","3x^4"],"a":1,"e":"Power raised to a power: multiply exponents, 4*3=12, so x^12.","d":2},{"q":"What is the square root of 144?","c":["14","16","12","24"],"a":2,"e":"12*12 = 144, so sqrt(144) = 12.","d":1},{"q":"Simplify: sqrt(50)","c":["5*sqrt(2)","2*sqrt(5)","25*sqrt(2)","10*sqrt(5)"],"a":0,"e":"50 = 25*2, sqrt(25)=5, so sqrt(50) = 5*sqrt(2).","d":2},{"q":"Solve for x: 3x + 7 = 22","c":["3","5","15","9"],"a":1,"e":"Subtract 7: 3x=15. Divide by 3: x=5.","d":1},{"q":"Solve for x: 2(x - 4) = 10","c":["9","3","7","1"],"a":0,"e":"Distribute: 2x-8=10. Add 8: 2x=18. Divide by 2: x=9.","d":2},{"q":"Solve for x: x/4 - 3 = 2","c":["5","-4","8","20"],"a":3,"e":"Add 3: x/4=5. Multiply by 4: x=20.","d":1},{"q":"Solve the system: x + y = 10 and x - y = 4. What is x?","c":["3","6","7","8"],"a":2,"e":"Add the equations: 2x=14, so x=7 (and y=3).","d":2},{"q":"Solve the system: 2x + y = 11 and y = x - 1. What is y?","c":["4","3","5","2"],"a":1,"e":"Substitute: 2x+(x-1)=11, so 3x=12, x=4. Then y=4-1=3.","d":3},{"q":"Solve the inequality: 2x - 5 > 7","c":["x > 1","x < 6","x > 12","x > 6"],"a":3,"e":"Add 5: 2x>12. Divide by 2: x>6.","d":2},{"q":"Solve: -3x < 9","c":["x < -3","x > -3","x < 3","x > 3"],"a":1,"e":"Divide by -3 and flip the inequality: x > -3.","d":3},{"q":"Multiply: (x + 3)(x + 5)","c":["x^2 + 8x + 15","x^2 + 15x + 8","x^2 + 8x + 8","x^2 + 15"],"a":0,"e":"FOIL: x^2 +5x+3x+15 = x^2+8x+15.","d":2},{"q":"Multiply: (x - 4)(x + 4)","c":["x^2 + 16","x^2 - 8x + 16","x^2 - 16","x^2 - 8"],"a":2,"e":"Difference of squares: (x-4)(x+4) = x^2 - 16.","d":2},{"q":"Factor: x^2 + 7x + 12","c":["(x+3)(x+4)","(x+2)(x+6)","(x+1)(x+12)","(x-3)(x-4)"],"a":0,"e":"Need two numbers multiplying to 12 and adding to 7: 3 and 4. So (x+3)(x+4).","d":2},{"q":"Factor: x^2 - 9x + 20","c":["(x-2)(x-10)","(x-4)(x-5)","(x+4)(x+5)","(x-1)(x-20)"],"a":1,"e":"Two numbers multiplying to 20, adding to -9: -4 and -5. So (x-4)(x-5).","d":3},{"q":"Factor completely: 6x^2 + 9x","c":["3x(2x+3)","3(2x^2+3x)","x(6x+9)","6x(x+9)"],"a":0,"e":"GCF of 6x^2 and 9x is 3x. Factor out: 3x(2x+3).","d":2},{"q":"Solve: x^2 - 5x + 6 = 0","c":["x=-2 or x=-3","x=1 or x=6","x=2 or x=4","x=2 or x=3"],"a":3,"e":"Factor: (x-2)(x-3)=0, so x=2 or x=3.","d":3},{"q":"Solve: x^2 = 49","c":["x=7 only","x=7 or x=-7","x=24.5","x=-7 only"],"a":1,"e":"Take the square root of both sides: x = +7 or -7.","d":2},{"q":"Evaluate 2x^2 - 3x + 1 when x = 3","c":["10","19","28","8"],"a":0,"e":"2(9)-3(3)+1 = 18-9+1 = 10.","d":2},{"q":"What is the greatest common factor (GCF) of 24 and 36?","c":["6","4","12","72"],"a":2,"e":"24=2^3*3, 36=2^2*3^2. Common: 2^2*3 = 12.","d":2},{"q":"What is the least common multiple (LCM) of 6 and 8?","c":["48","24","14","2"],"a":1,"e":"6=2*3, 8=2^3. LCM = 2^3*3 = 24.","d":2},{"q":"Which of the following is a prime number?","c":["21","27","29","33"],"a":2,"e":"29 has no divisors other than 1 and 29. The others are composite (21=3*7, 27=3^3, 33=3*11).","d":1},{"q":"The angles of a triangle are 50 degrees and 60 degrees. What is the third angle?","c":["80 degrees","70 degrees","110 degrees","60 degrees"],"a":1,"e":"Angles sum to 180. 180-50-60 = 70 degrees.","d":1},{"q":"A rectangle has length 9 and width 4. What is its area?","c":["13","26","36","45"],"a":2,"e":"Area = length * width = 9*4 = 36.","d":1},{"q":"A rectangle has length 9 and width 4. What is its perimeter?","c":["26","36","13","22"],"a":0,"e":"Perimeter = 2(l+w) = 2(9+4) = 2*13 = 26.","d":1},{"q":"What is the area of a triangle with base 10 and height 6?","c":["60","16","20","30"],"a":3,"e":"Area = (1/2)*base*height = (1/2)*10*6 = 30.","d":1},{"q":"A circle has radius 5. What is its area? (use pi)","c":["10*pi","25*pi","5*pi","50*pi"],"a":1,"e":"Area = pi*r^2 = pi*5^2 = 25*pi.","d":2},{"q":"A circle has radius 7. What is its circumference? (use pi)","c":["14*pi","49*pi","7*pi","21*pi"],"a":0,"e":"Circumference = 2*pi*r = 2*pi*7 = 14*pi.","d":2},{"q":"A right triangle has legs 6 and 8. What is the hypotenuse?","c":["14","10","48","12"],"a":1,"e":"Pythagorean: c^2 = 6^2+8^2 = 36+64 = 100, so c = 10.","d":1},{"q":"A right triangle has a hypotenuse of 13 and one leg of 5. What is the other leg?","c":["8","12","18","144"],"a":1,"e":"Leg^2 = 13^2 - 5^2 = 169-25 = 144, so leg = 12.","d":2},{"q":"What is the volume of a cube with edge length 4?","c":["16","12","48","64"],"a":3,"e":"Volume = side^3 = 4^3 = 64.","d":1},{"q":"What is the volume of a rectangular box 3 by 4 by 5?","c":["12","60","47","120"],"a":1,"e":"Volume = l*w*h = 3*4*5 = 60.","d":1},{"q":"What is the surface area of a cube with edge length 3?","c":["27","9","54","36"],"a":2,"e":"Surface area = 6*side^2 = 6*9 = 54.","d":3},{"q":"What is the slope of the line through points (1, 2) and (4, 11)?","c":["3","9/5","1/3","13/5"],"a":0,"e":"Slope = (11-2)/(4-1) = 9/3 = 3.","d":2},{"q":"What is the distance between points (0, 0) and (3, 4)?","c":["7","5","12","25"],"a":1,"e":"Distance = sqrt(3^2+4^2) = sqrt(9+16) = sqrt(25) = 5.","d":2},{"q":"What is the midpoint of the segment from (2, 4) to (8, 10)?","c":["(5, 7)","(6, 6)","(10, 14)","(3, 3)"],"a":0,"e":"Midpoint = ((2+8)/2, (4+10)/2) = (5, 7).","d":3},{"q":"In a right triangle, the side opposite a 30 degree angle is 5 and the hypotenuse is 10. What is sin(30 degrees)?","c":["2","1/2","5/3","sqrt(3)/2"],"a":1,"e":"sin = opposite/hypotenuse = 5/10 = 1/2.","d":2},{"q":"What is 12 - 4 * 2 + 6?","c":["22","10","16","2"],"a":1,"e":"Multiply first: 4*2=8. Then 12-8+6 = 10.","d":1},{"q":"Solve for x: 5x - 9 = 16","c":["4","7","5","3"],"a":2,"e":"Add 9: 5x=25. Divide by 5: x=5.","d":1},{"q":"What is the perimeter of a square with side length 8?","c":["16","64","32","24"],"a":2,"e":"Perimeter = 4*side = 4*8 = 32.","d":1},{"q":"What is the value of 2^5?","c":["10","32","25","16"],"a":1,"e":"2^5 = 2*2*2*2*2 = 32.","d":1},{"q":"Simplify: x^8 / x^3","c":["x^5","x^11","x^24","x^2"],"a":0,"e":"When dividing like bases, subtract exponents: 8-3=5, so x^5.","d":2},{"q":"What is the value of 5^0?","c":["0","5","1","undefined"],"a":2,"e":"Any nonzero number raised to the power 0 equals 1.","d":1},{"q":"Solve the system: 3x + 2y = 16 and x = y + 2. What is x?","c":["2","6","4","3"],"a":2,"e":"Substitute: 3(y+2)+2y=16, so 5y+6=16, 5y=10, y=2. Then x=2+2=4.","d":3},{"q":"Solve: 2x^2 - 8 = 0","c":["x=2 or x=-2","x=4 only","x=2 only","x=8 or x=-8"],"a":0,"e":"Add 8: 2x^2=8, so x^2=4, giving x=2 or x=-2.","d":3},{"q":"Factor: x^2 - 6x + 9","c":["(x-3)(x+3)","(x-3)^2","(x+3)^2","(x-9)(x-1)"],"a":1,"e":"Perfect square: two numbers multiplying to 9, adding to -6 are -3 and -3, so (x-3)^2.","d":3},{"q":"Multiply: (2x + 1)(x + 4)","c":["2x^2 + 9x + 4","2x^2 + 4x + 4","2x^2 + 8x + 4","2x^2 + 5x + 4"],"a":0,"e":"FOIL: 2x^2+8x+x+4 = 2x^2+9x+4.","d":3},{"q":"Solve: x^2 + 2x - 15 = 0","c":["x=3 or x=5","x=-3 or x=5","x=3 or x=-5","x=-3 or x=-5"],"a":2,"e":"Factor: (x+5)(x-3)=0, so x=-5 or x=3.","d":3},{"q":"What is the slope of the line through points (2, 5) and (6, 1)?","c":["-1","1","-2","2"],"a":0,"e":"Slope = (1-5)/(6-2) = -4/4 = -1.","d":3},{"q":"What is the distance between points (1, 2) and (4, 6)?","c":["7","25","5","sqrt(7)"],"a":2,"e":"Distance = sqrt((4-1)^2+(6-2)^2) = sqrt(9+16) = sqrt(25) = 5.","d":3},{"q":"A right triangle has legs 5 and 12. What is the hypotenuse?","c":["17","13","15","60"],"a":1,"e":"c^2 = 5^2+12^2 = 25+144 = 169, so c = 13.","d":2},{"q":"In a right triangle, the side adjacent to an angle is 4 and the hypotenuse is 5. What is the cosine of that angle?","c":["3/5","5/4","4/5","4/3"],"a":2,"e":"cos = adjacent/hypotenuse = 4/5.","d":3},{"q":"What is the volume of a cylinder with radius 3 and height 5? (use pi)","c":["15*pi","45*pi","30*pi","90*pi"],"a":1,"e":"Volume = pi*r^2*h = pi*9*5 = 45*pi.","d":3},{"q":"A triangle is isosceles with two equal base angles. If the vertex angle is 40 degrees, what is each base angle?","c":["70 degrees","60 degrees","80 degrees","50 degrees"],"a":0,"e":"Base angles are equal and sum with 40 to 180. So 2x+40=180, 2x=140, x=70 degrees.","d":3},{"q":"What is 30% of 80?","c":["18","24","26","32"],"a":1,"e":"0.30*80 = 24.","d":1},{"q":"Solve for x: (x + 2)/3 = 4","c":["6","14","10","12"],"a":2,"e":"Multiply by 3: x+2=12. Subtract 2: x=10.","d":2},{"q":"What is the area of a trapezoid with parallel sides 6 and 10 and height 4?","c":["32","40","64","28"],"a":0,"e":"Area = (1/2)(b1+b2)*h = (1/2)(6+10)*4 = (1/2)(16)(4) = 32.","d":3}];
QBANK["WK"] = [{"q":"Abundant most nearly means:","c":["plentiful","scarce","hidden","fragile"],"a":0,"e":"Abundant means existing in large quantities; plentiful is the synonym.","d":2},{"q":"The witness gave a candid account of the accident. Candid most nearly means:","c":["fearful","frank","lengthy","biased"],"a":1,"e":"Candid means honest and straightforward; frank is the synonym.","d":3},{"q":"Diminish most nearly means:","c":["repair","confuse","decrease","gather"],"a":2,"e":"Diminish means to make or become smaller; decrease is the synonym.","d":2},{"q":"Vital most nearly means:","c":["optional","ancient","quiet","essential"],"a":3,"e":"Vital means absolutely necessary; essential is the synonym.","d":1},{"q":"The instructions were ambiguous and confused the recruits. Ambiguous most nearly means:","c":["unclear","detailed","forceful","helpful"],"a":0,"e":"Ambiguous means open to more than one meaning; unclear is the synonym.","d":3},{"q":"Conceal most nearly means:","c":["reveal","hide","destroy","carry"],"a":1,"e":"Conceal means to keep from sight; hide is the synonym.","d":1},{"q":"Rigid most nearly means:","c":["smooth","heavy","stiff","empty"],"a":2,"e":"Rigid means unable to bend; stiff is the synonym.","d":2},{"q":"Novice most nearly means:","c":["expert","leader","traveler","beginner"],"a":3,"e":"A novice is a person new to something; beginner is the synonym.","d":2},{"q":"The general's tactics were prudent and avoided needless losses. Prudent most nearly means:","c":["reckless","cautious","cruel","sudden"],"a":1,"e":"Prudent means showing careful good judgment; cautious is the synonym.","d":3},{"q":"Terminate most nearly means:","c":["begin","end","extend","repeat"],"a":1,"e":"Terminate means to bring to an end; end is the synonym.","d":1},{"q":"Fatigue most nearly means:","c":["tiredness","hunger","fear","boredom"],"a":0,"e":"Fatigue means extreme tiredness; tiredness is the synonym.","d":1},{"q":"Vacant most nearly means:","c":["crowded","locked","empty","dusty"],"a":2,"e":"Vacant means not occupied; empty is the synonym.","d":2},{"q":"The soldier remained vigilant throughout the long night. Vigilant most nearly means:","c":["sleepy","cheerful","silent","watchful"],"a":3,"e":"Vigilant means keeping careful watch; watchful is the synonym.","d":2},{"q":"Obstinate most nearly means:","c":["flexible","stubborn","generous","timid"],"a":1,"e":"Obstinate means refusing to change one's mind; stubborn is the synonym.","d":3},{"q":"Sufficient most nearly means:","c":["enough","extra","rare","cheap"],"a":0,"e":"Sufficient means as much as is needed; enough is the synonym.","d":2},{"q":"Hostile most nearly means:","c":["friendly","curious","unfriendly","calm"],"a":2,"e":"Hostile means showing strong opposition or dislike; unfriendly is the synonym.","d":1},{"q":"The coach offered a concise summary of the plan. Concise most nearly means:","c":["wordy","brief","confusing","loud"],"a":1,"e":"Concise means giving information clearly and in few words; brief is the synonym.","d":2},{"q":"Hazardous most nearly means:","c":["safe","useful","sturdy","dangerous"],"a":3,"e":"Hazardous means risky; dangerous is the synonym.","d":2},{"q":"Reluctant most nearly means:","c":["eager","unwilling","quick","honest"],"a":1,"e":"Reluctant means hesitant to do something; unwilling is the synonym.","d":2},{"q":"Tedious most nearly means:","c":["boring","exciting","brief","easy"],"a":0,"e":"Tedious means long and tiresome; boring is the synonym.","d":2},{"q":"The new policy will augment the unit's resources. Augment most nearly means:","c":["reduce","increase","replace","ignore"],"a":1,"e":"Augment means to make larger; increase is the synonym.","d":3},{"q":"Frail most nearly means:","c":["bold","wide","weak","loud"],"a":2,"e":"Frail means weak and delicate; weak is the synonym.","d":2},{"q":"Genuine most nearly means:","c":["fake","cheap","rare","real"],"a":3,"e":"Genuine means truly what it is said to be; real is the synonym.","d":1},{"q":"Summit most nearly means:","c":["base","peak","valley","slope"],"a":1,"e":"Summit means the highest point; peak is the synonym.","d":1},{"q":"The mechanic gave a meticulous inspection of the engine. Meticulous most nearly means:","c":["thorough","careless","hasty","brief"],"a":0,"e":"Meticulous means showing great attention to detail; thorough is the synonym.","d":3},{"q":"Initiate most nearly means:","c":["finish","begin","delay","cancel"],"a":1,"e":"Initiate means to start; begin is the synonym.","d":2},{"q":"Pungent most nearly means:","c":["bland","sweet","sharp","faint"],"a":2,"e":"Pungent means having a strong, sharp smell or taste; sharp is the synonym.","d":3},{"q":"Lenient most nearly means:","c":["strict","angry","fair","merciful"],"a":3,"e":"Lenient means not harsh in punishment; merciful is the synonym.","d":3},{"q":"The river was placid in the early morning. Placid most nearly means:","c":["stormy","calm","muddy","rapid"],"a":1,"e":"Placid means calm and peaceful; calm is the synonym.","d":3},{"q":"Deteriorate most nearly means:","c":["worsen","improve","clean","build"],"a":0,"e":"Deteriorate means to become worse; worsen is the synonym.","d":2},{"q":"Adjacent most nearly means:","c":["distant","neighboring","opposite","hidden"],"a":1,"e":"Adjacent means next to or near; neighboring is the synonym.","d":2},{"q":"Scrutinize most nearly means:","c":["glance","ignore","examine","approve"],"a":2,"e":"Scrutinize means to examine closely; examine is the synonym.","d":3},{"q":"The crowd grew boisterous after the win. Boisterous most nearly means:","c":["quiet","tired","polite","rowdy"],"a":3,"e":"Boisterous means noisy and energetic; rowdy is the synonym.","d":3},{"q":"Feasible most nearly means:","c":["possible","costly","unlikely","required"],"a":0,"e":"Feasible means able to be done; possible is the synonym.","d":2},{"q":"Mundane most nearly means:","c":["thrilling","ordinary","rare","sacred"],"a":1,"e":"Mundane means dull and commonplace; ordinary is the synonym.","d":3},{"q":"Vindicate most nearly means:","c":["accuse","punish","clear","doubt"],"a":2,"e":"Vindicate means to clear of blame; clear is the synonym.","d":3},{"q":"The recruit showed remarkable tenacity during training. Tenacity most nearly means:","c":["laziness","talent","fear","persistence"],"a":3,"e":"Tenacity means determination and persistence; persistence is the synonym.","d":3},{"q":"Arid most nearly means:","c":["dry","cold","fertile","windy"],"a":0,"e":"Arid means having little rainfall; dry is the synonym.","d":2},{"q":"Benevolent most nearly means:","c":["cruel","kind","wealthy","strict"],"a":1,"e":"Benevolent means well meaning and kindly; kind is the synonym.","d":3},{"q":"Fluctuate most nearly means:","c":["stabilize","stop","vary","rise"],"a":2,"e":"Fluctuate means to rise and fall irregularly; vary is the synonym.","d":2},{"q":"The judge issued a stern warning. Stern most nearly means:","c":["gentle","brief","unclear","severe"],"a":3,"e":"Stern means strict and serious; severe is the synonym.","d":1},{"q":"Abolish most nearly means:","c":["create","eliminate","enforce","delay"],"a":1,"e":"Abolish means to do away with formally; eliminate is the synonym.","d":2},{"q":"Eloquent most nearly means:","c":["articulate","awkward","quiet","rude"],"a":0,"e":"Eloquent means fluent and persuasive in speech; articulate is the synonym.","d":3},{"q":"Imminent most nearly means:","c":["distant","approaching","unlikely","past"],"a":1,"e":"Imminent means about to happen; approaching is the synonym.","d":3},{"q":"The trail was treacherous after the storm. Treacherous most nearly means:","c":["smooth","scenic","dangerous","narrow"],"a":2,"e":"Treacherous means hazardous and unsafe; dangerous is the synonym.","d":2},{"q":"Apprehensive most nearly means:","c":["confident","curious","tired","anxious"],"a":3,"e":"Apprehensive means worried that something bad will happen; anxious is the synonym.","d":3},{"q":"Resilient most nearly means:","c":["fragile","tough","heavy","slow"],"a":1,"e":"Resilient means able to recover quickly; tough is the synonym.","d":2},{"q":"The proposal received unanimous support. Unanimous most nearly means:","c":["united","divided","reluctant","partial"],"a":0,"e":"Unanimous means agreed by everyone; united is the synonym.","d":2},{"q":"Squander most nearly means:","c":["save","waste","earn","share"],"a":1,"e":"Squander means to spend wastefully; waste is the synonym.","d":3},{"q":"Verify most nearly means:","c":["doubt","reject","confirm","guess"],"a":2,"e":"Verify means to check the truth of something; confirm is the synonym.","d":1},{"q":"Rapid most nearly means:","c":["slow","fast","heavy","loud"],"a":1,"e":"Rapid means happening quickly; fast is the synonym.","d":1},{"q":"The firefighter was brave under pressure. Brave most nearly means:","c":["timid","weary","courageous","clumsy"],"a":2,"e":"Brave means showing courage; courageous is the synonym.","d":1},{"q":"Enormous most nearly means:","c":["huge","tiny","plain","narrow"],"a":0,"e":"Enormous means very large; huge is the synonym.","d":1},{"q":"Repair most nearly means:","c":["break","fix","sell","hide"],"a":1,"e":"Repair means to restore to good condition; fix is the synonym.","d":1},{"q":"The hikers felt weary after the climb. Weary most nearly means:","c":["alert","tired","angry","hungry"],"a":1,"e":"Weary means very tired; tired is the synonym.","d":1},{"q":"Quiet most nearly means:","c":["loud","busy","silent","bright"],"a":2,"e":"Quiet means making little or no noise; silent is the synonym.","d":1},{"q":"Begin most nearly means:","c":["stop","finish","pause","start"],"a":3,"e":"Begin means to set in motion; start is the synonym.","d":1},{"q":"Select most nearly means:","c":["choose","reject","gather","count"],"a":0,"e":"Select means to pick out; choose is the synonym.","d":1},{"q":"The road was narrow near the bridge. Narrow most nearly means:","c":["wide","tight","steep","long"],"a":1,"e":"Narrow means of small width; tight is the synonym.","d":1},{"q":"Damp most nearly means:","c":["dry","warm","moist","clean"],"a":2,"e":"Damp means slightly wet; moist is the synonym.","d":1},{"q":"Permit most nearly means:","c":["forbid","punish","delay","allow"],"a":3,"e":"Permit means to give consent; allow is the synonym.","d":1},{"q":"Sturdy most nearly means:","c":["robust","flimsy","smooth","hollow"],"a":0,"e":"Sturdy means strongly built; robust is the synonym.","d":2},{"q":"The clerk made an error on the form. Error most nearly means:","c":["choice","mistake","total","record"],"a":1,"e":"An error is something done wrong; mistake is the synonym.","d":1},{"q":"Gather most nearly means:","c":["scatter","sort","collect","spend"],"a":2,"e":"Gather means to bring together; collect is the synonym.","d":1},{"q":"Bewilder most nearly means:","c":["calm","please","amuse","confuse"],"a":3,"e":"Bewilder means to puzzle greatly; confuse is the synonym.","d":2},{"q":"Abate most nearly means:","c":["lessen","increase","begin","stiffen"],"a":0,"e":"Abate means to become less intense; lessen is the synonym.","d":3},{"q":"The senator's argument was tenuous and easily refuted. Tenuous most nearly means:","c":["solid","weak","lengthy","clever"],"a":1,"e":"Tenuous means slight or flimsy; weak is the synonym.","d":3},{"q":"Frugal most nearly means:","c":["generous","wasteful","thrifty","wealthy"],"a":2,"e":"Frugal means careful with money; thrifty is the synonym.","d":3},{"q":"The crew worked in unison to launch the boat. Unison most nearly means:","c":["conflict","silence","delay","harmony"],"a":3,"e":"Unison means acting together as one; harmony is the synonym.","d":2},{"q":"Brisk most nearly means:","c":["quick","slow","gentle","heavy"],"a":0,"e":"Brisk means quick and energetic; quick is the synonym.","d":2},{"q":"The orders were explicit and left no doubt. Explicit most nearly means:","c":["vague","clear","secret","brief"],"a":1,"e":"Explicit means stated clearly and in detail; clear is the synonym.","d":3},{"q":"Mitigate most nearly means:","c":["worsen","ignore","ease","cause"],"a":2,"e":"Mitigate means to make less severe; ease is the synonym.","d":3},{"q":"The commander gave a succinct briefing. Succinct most nearly means:","c":["lengthy","vague","loud","brief"],"a":3,"e":"Succinct means expressed in few words; brief is the synonym.","d":3},{"q":"Loathe most nearly means:","c":["detest","admire","forget","permit"],"a":0,"e":"Loathe means to feel intense dislike; detest is the synonym.","d":2},{"q":"The lawyer's tone was condescending toward the jury. Condescending most nearly means:","c":["humble","patronizing","friendly","nervous"],"a":1,"e":"Condescending means showing superiority; patronizing is the synonym.","d":3},{"q":"Sparse most nearly means:","c":["dense","heavy","scant","wide"],"a":2,"e":"Sparse means thinly scattered; scant is the synonym.","d":2},{"q":"The new sergeant was zealous about safety drills. Zealous most nearly means:","c":["lazy","calm","careless","eager"],"a":3,"e":"Zealous means full of energetic enthusiasm; eager is the synonym.","d":3},{"q":"Halt most nearly means:","c":["stop","speed","turn","climb"],"a":0,"e":"Halt means to bring to a stop; stop is the synonym.","d":1},{"q":"The veteran kept his composure during the emergency. Composure most nearly means:","c":["panic","poise","anger","haste"],"a":1,"e":"Composure means calm self-control; poise is the synonym.","d":2},{"q":"Inept most nearly means:","c":["skilled","brave","incompetent","loyal"],"a":2,"e":"Inept means lacking skill; incompetent is the synonym.","d":3}];
QBANK["PC"] = [{"q":"Passage: Honeybees communicate the location of food through a movement known as the waggle dance. By moving in a figure-eight pattern and vibrating its body, a returning bee tells the others both the direction and the distance of a flower patch. The angle of the dance relative to the sun points the way, while the length of the waggle indicates how far the food is.\n\nQuestion: What is the main idea of this passage?","c":["Honeybees use a waggle dance to share the location of food","Honeybees prefer flowers that grow near the hive","The sun controls when honeybees leave the hive","Bees vibrate their bodies only to stay warm"],"a":0,"e":"The passage opens by stating bees communicate food location through the waggle dance and the rest describes how, making this the main idea.","d":3},{"q":"Passage: Honeybees communicate the location of food through a movement known as the waggle dance. By moving in a figure-eight pattern and vibrating its body, a returning bee tells the others both the direction and the distance of a flower patch. The angle of the dance relative to the sun points the way, while the length of the waggle indicates how far the food is.\n\nQuestion: According to the passage, what does the length of the waggle indicate?","c":["The size of the flower patch","The number of bees in the hive","How far away the food is","The time of day"],"a":2,"e":"The passage states the length of the waggle indicates how far the food is.","d":1},{"q":"Passage: Honeybees communicate the location of food through a movement known as the waggle dance. By moving in a figure-eight pattern and vibrating its body, a returning bee tells the others both the direction and the distance of a flower patch. The angle of the dance relative to the sun points the way, while the length of the waggle indicates how far the food is.\n\nQuestion: It can be inferred from the passage that without the sun as a reference, a watching bee would most likely have trouble determining the:","c":["distance to the food","direction to the food","number of flowers","color of the flowers"],"a":1,"e":"The passage says the angle of the dance relative to the sun points the way (direction), so losing the sun reference would affect determining direction.","d":3},{"q":"Passage: In the early 1800s, lighthouse keepers lived isolated lives along rocky coasts. Their main duty was to keep the lamp burning every night so that passing ships could avoid the dangerous shoreline. A keeper had to trim the wick, refill the oil, and polish the glass lenses, often climbing the tower several times before dawn.\n\nQuestion: What was the lighthouse keeper's main duty?","c":["To rescue sailors from sinking ships","To keep the lamp burning every night","To map the rocky coastline","To deliver mail to nearby towns"],"a":1,"e":"The passage states the keeper's main duty was to keep the lamp burning every night.","d":1},{"q":"Passage: In the early 1800s, lighthouse keepers lived isolated lives along rocky coasts. Their main duty was to keep the lamp burning every night so that passing ships could avoid the dangerous shoreline. A keeper had to trim the wick, refill the oil, and polish the glass lenses, often climbing the tower several times before dawn.\n\nQuestion: As used in the passage, the word \"isolated\" most nearly means:","c":["wealthy","crowded","cut off from others","constantly traveling"],"a":2,"e":"The passage describes keepers living alone along remote rocky coasts, so isolated means cut off from others.","d":2},{"q":"Passage: In the early 1800s, lighthouse keepers lived isolated lives along rocky coasts. Their main duty was to keep the lamp burning every night so that passing ships could avoid the dangerous shoreline. A keeper had to trim the wick, refill the oil, and polish the glass lenses, often climbing the tower several times before dawn.\n\nQuestion: It can be inferred from the passage that the keeper's work was:","c":["demanding and repetitive","mostly done during daylight","shared by a large crew","easy and relaxing"],"a":0,"e":"The passage lists repeated chores and notes the keeper often climbed the tower several times before dawn, implying demanding, repetitive work.","d":3},{"q":"Passage: When a new employee joins our department, we assign each one a mentor for the first month. The mentor answers questions, explains office procedures, and introduces the newcomer to coworkers. We have found that workers who receive this guidance settle into their roles far more quickly than those left to figure things out alone.\n\nQuestion: According to the passage, how long is a new employee assigned a mentor?","c":["For one week","For the first month","For one year","Until they request a transfer"],"a":1,"e":"The passage states each new employee is assigned a mentor for the first month.","d":1},{"q":"Passage: When a new employee joins our department, we assign each one a mentor for the first month. The mentor answers questions, explains office procedures, and introduces the newcomer to coworkers. We have found that workers who receive this guidance settle into their roles far more quickly than those left to figure things out alone.\n\nQuestion: What is the author's main point about the mentoring program?","c":["Mentors are paid extra for their work","New employees rarely ask questions","Guidance helps new workers adjust faster","Most coworkers dislike meeting newcomers"],"a":2,"e":"The passage concludes that workers who receive this guidance settle into their roles far more quickly, the author's main point.","d":3},{"q":"Passage: When a new employee joins our department, we assign each one a mentor for the first month. The mentor answers questions, explains office procedures, and introduces the newcomer to coworkers. We have found that workers who receive this guidance settle into their roles far more quickly than those left to figure things out alone.\n\nQuestion: The author's attitude toward the mentoring program can best be described as:","c":["doubtful","approving","indifferent","alarmed"],"a":1,"e":"The author credits the program with helping workers settle in faster, showing an approving attitude.","d":3},{"q":"Passage: Recycling aluminum cans saves a remarkable amount of energy. Producing a new can from recycled aluminum uses only about five percent of the energy needed to make one from raw ore. Because of this, a single recycled can can power a television for several hours' worth of saved energy.\n\nQuestion: According to the passage, making a can from recycled aluminum uses about what fraction of the energy of making one from raw ore?","c":["Five percent","Fifty percent","Ninety percent","One hundred percent"],"a":0,"e":"The passage states producing a can from recycled aluminum uses only about five percent of the energy needed to make one from raw ore.","d":1},{"q":"Passage: Recycling aluminum cans saves a remarkable amount of energy. Producing a new can from recycled aluminum uses only about five percent of the energy needed to make one from raw ore. Because of this, a single recycled can can power a television for several hours' worth of saved energy.\n\nQuestion: What is the main idea of this passage?","c":["Aluminum cans are difficult to recycle","Recycling aluminum cans saves a great deal of energy","Televisions use very little electricity","Raw ore is cheaper than recycled aluminum"],"a":1,"e":"The opening sentence states recycling aluminum cans saves a remarkable amount of energy, which the rest supports.","d":2},{"q":"Passage: Recycling aluminum cans saves a remarkable amount of energy. Producing a new can from recycled aluminum uses only about five percent of the energy needed to make one from raw ore. Because of this, a single recycled can can power a television for several hours' worth of saved energy.\n\nQuestion: It can be inferred from the passage that making aluminum from raw ore is:","c":["far more energy-intensive than recycling","slightly cheaper than recycling","done only in small factories","better for the environment"],"a":0,"e":"Since recycling uses only five percent of the energy of raw ore production, it follows that making aluminum from raw ore is far more energy-intensive.","d":3},{"q":"Passage: The desert may look lifeless during the heat of the day, but it comes alive after dark. Many animals, such as kangaroo rats and certain owls, are nocturnal, sleeping in burrows or shade while the sun is high. They emerge at night to hunt and forage when cooler temperatures make moving around far less dangerous.\n\nQuestion: As used in the passage, the word \"nocturnal\" most nearly means:","c":["active at night","unable to see","living underground forever","afraid of water"],"a":0,"e":"The passage explains these animals sleep during the day and emerge at night, so nocturnal means active at night.","d":2},{"q":"Passage: The desert may look lifeless during the heat of the day, but it comes alive after dark. Many animals, such as kangaroo rats and certain owls, are nocturnal, sleeping in burrows or shade while the sun is high. They emerge at night to hunt and forage when cooler temperatures make moving around far less dangerous.\n\nQuestion: According to the passage, why do these desert animals come out at night?","c":["Because there is more food at night","Because cooler temperatures make moving around less dangerous","Because they cannot sleep in burrows","Because other animals chase them away by day"],"a":1,"e":"The passage states they emerge at night when cooler temperatures make moving around far less dangerous.","d":1},{"q":"Passage: The desert may look lifeless during the heat of the day, but it comes alive after dark. Many animals, such as kangaroo rats and certain owls, are nocturnal, sleeping in burrows or shade while the sun is high. They emerge at night to hunt and forage when cooler temperatures make moving around far less dangerous.\n\nQuestion: What is the main idea of the passage?","c":["Kangaroo rats are the most common desert animal","The desert has no plants","Deserts are too hot for any life to survive","The desert is full of life that is active mainly at night"],"a":3,"e":"The passage contrasts the seemingly lifeless daytime desert with nighttime activity, making the main idea that desert life is active mainly at night.","d":2},{"q":"Passage: Before refrigeration was common, people preserved food by salting, drying, or smoking it. These methods removed moisture or created conditions in which bacteria could not easily grow. A barrel of salted fish or a string of dried peppers could last through an entire winter, allowing families to eat well long after the harvest had ended.\n\nQuestion: According to the passage, why did salting and drying help preserve food?","c":["They added flavor that people enjoyed","They removed moisture or created conditions where bacteria could not easily grow","They kept food frozen solid","They made food lighter to carry"],"a":1,"e":"The passage states these methods removed moisture or created conditions in which bacteria could not easily grow.","d":2},{"q":"Passage: Before refrigeration was common, people preserved food by salting, drying, or smoking it. These methods removed moisture or created conditions in which bacteria could not easily grow. A barrel of salted fish or a string of dried peppers could last through an entire winter, allowing families to eat well long after the harvest had ended.\n\nQuestion: It can be inferred from the passage that, without these methods, much food would have:","c":["tasted better","lasted even longer","spoiled before it could be eaten","been easier to transport"],"a":2,"e":"Since the methods prevented bacterial growth and let food last through winter, without them food would likely have spoiled before being eaten.","d":3},{"q":"Passage: Before refrigeration was common, people preserved food by salting, drying, or smoking it. These methods removed moisture or created conditions in which bacteria could not easily grow. A barrel of salted fish or a string of dried peppers could last through an entire winter, allowing families to eat well long after the harvest had ended.\n\nQuestion: Which of the following is given as an example of preserved food in the passage?","c":["Fresh milk","A string of dried peppers","A bowl of soup","A loaf of warm bread"],"a":1,"e":"The passage names a string of dried peppers as an example of food that could last through the winter.","d":1},{"q":"Passage: Most modern bridges fall into a few basic types. A beam bridge rests on supports at each end and works well over short distances. For longer spans, engineers often choose a suspension bridge, in which the roadway hangs from cables draped over tall towers. The choice depends on the width of the gap, the weight the bridge must carry, and the cost of building it.\n\nQuestion: According to the passage, on what does the choice of bridge type depend?","c":["The color of the towers and cables","The width of the gap, the weight to be carried, and the cost","The number of workers available","The season in which it is built"],"a":1,"e":"The passage states the choice depends on the width of the gap, the weight the bridge must carry, and the cost of building it.","d":1},{"q":"Passage: Most modern bridges fall into a few basic types. A beam bridge rests on supports at each end and works well over short distances. For longer spans, engineers often choose a suspension bridge, in which the roadway hangs from cables draped over tall towers. The choice depends on the width of the gap, the weight the bridge must carry, and the cost of building it.\n\nQuestion: It can be inferred from the passage that a beam bridge would be a poor choice for:","c":["a very short stream","crossing a wide river in a single span","a quiet country road","a footpath over a ditch"],"a":1,"e":"The passage says beam bridges work well over short distances and suspension bridges are chosen for longer spans, so a beam bridge would be poor for a wide single span.","d":3},{"q":"Passage: Most modern bridges fall into a few basic types. A beam bridge rests on supports at each end and works well over short distances. For longer spans, engineers often choose a suspension bridge, in which the roadway hangs from cables draped over tall towers. The choice depends on the width of the gap, the weight the bridge must carry, and the cost of building it.\n\nQuestion: In a suspension bridge, what holds up the roadway?","c":["Solid stone walls beneath it","Cables draped over tall towers","A single central pillar","Floating barrels"],"a":1,"e":"The passage states that in a suspension bridge the roadway hangs from cables draped over tall towers.","d":2},{"q":"Passage: Maria had practiced the violin for months, but the night before the recital her hands would not stop trembling. She kept picturing herself forgetting the notes in front of a silent crowd. Yet when she finally stepped onto the stage and drew the bow across the strings, the familiar melody flowed without a single mistake, and she wondered why she had ever doubted herself.\n\nQuestion: How did Maria most likely feel the night before the recital?","c":["Bored and sleepy","Confident and proud","Nervous and worried","Angry and resentful"],"a":2,"e":"The passage says her hands trembled and she pictured forgetting the notes, showing she felt nervous and worried.","d":2},{"q":"Passage: Maria had practiced the violin for months, but the night before the recital her hands would not stop trembling. She kept picturing herself forgetting the notes in front of a silent crowd. Yet when she finally stepped onto the stage and drew the bow across the strings, the familiar melody flowed without a single mistake, and she wondered why she had ever doubted herself.\n\nQuestion: What is the main idea of this passage?","c":["Maria's fears proved worse than the reality of performing","Maria had not practiced enough for the recital","The crowd was disappointed by Maria's playing","Maria decided to give up the violin"],"a":0,"e":"Maria feared failure but performed flawlessly and questioned her doubts, so the main idea is that her fears were worse than the reality.","d":3},{"q":"Passage: Maria had practiced the violin for months, but the night before the recital her hands would not stop trembling. She kept picturing herself forgetting the notes in front of a silent crowd. Yet when she finally stepped onto the stage and drew the bow across the strings, the familiar melody flowed without a single mistake, and she wondered why she had ever doubted herself.\n\nQuestion: According to the passage, what happened when Maria performed on stage?","c":["She forgot the notes halfway through","She played the melody without a single mistake","She refused to step onto the stage","She broke a string on her violin"],"a":1,"e":"The passage states the melody flowed without a single mistake once she began playing.","d":1},{"q":"Passage: Volunteers gathered at dawn to clean the riverbank, which had been littered with bottles and plastic bags for years. By noon they had filled dozens of trash bags, and the muddy shore looked clearer than anyone could remember. Several volunteers said they planned to return each month, hoping their small effort would inspire neighbors to keep the water clean.\n\nQuestion: According to the passage, what had the riverbank been littered with for years?","c":["Fallen leaves and branches","Bottles and plastic bags","Old fishing nets","Broken glass only"],"a":1,"e":"The passage states the riverbank had been littered with bottles and plastic bags for years.","d":2},{"q":"Passage: Volunteers gathered at dawn to clean the riverbank, which had been littered with bottles and plastic bags for years. By noon they had filled dozens of trash bags, and the muddy shore looked clearer than anyone could remember. Several volunteers said they planned to return each month, hoping their small effort would inspire neighbors to keep the water clean.\n\nQuestion: The tone of the passage can best be described as:","c":["bitter and hopeless","hopeful and encouraging","angry and accusing","cold and scientific"],"a":1,"e":"The volunteers' plan to return and inspire neighbors gives the passage a hopeful, encouraging tone.","d":3},{"q":"Passage: Volunteers gathered at dawn to clean the riverbank, which had been littered with bottles and plastic bags for years. By noon they had filled dozens of trash bags, and the muddy shore looked clearer than anyone could remember. Several volunteers said they planned to return each month, hoping their small effort would inspire neighbors to keep the water clean.\n\nQuestion: It can be inferred from the passage that the volunteers believe:","c":["the river can never be made clean","one cleanup will solve the problem completely","ongoing effort is needed to keep the river clean","the city should ignore the litter"],"a":2,"e":"Because the volunteers planned to return each month and hoped to inspire others, they believe ongoing effort is needed.","d":3},{"q":"Passage: The public library extended its hours this fall in response to student requests. It now stays open until eleven at night on weekdays, giving those who study late a quiet place to work. Staff also added more outlets and reading lamps so that students would not have to compete for the few spots near a power source.\n\nQuestion: According to the passage, until what time does the library now stay open on weekdays?","c":["Nine at night","Ten at night","Eleven at night","Midnight"],"a":2,"e":"The passage states the library now stays open until eleven at night on weekdays.","d":1},{"q":"Passage: The public library extended its hours this fall in response to student requests. It now stays open until eleven at night on weekdays, giving those who study late a quiet place to work. Staff also added more outlets and reading lamps so that students would not have to compete for the few spots near a power source.\n\nQuestion: Why did the staff add more outlets and reading lamps?","c":["To make the library more colorful","So students would not have to compete for spots near a power source","To replace the old computers","Because the old lamps had broken"],"a":1,"e":"The passage states the staff added outlets and lamps so students would not have to compete for the few spots near a power source.","d":2},{"q":"Passage: The public library extended its hours this fall in response to student requests. It now stays open until eleven at night on weekdays, giving those who study late a quiet place to work. Staff also added more outlets and reading lamps so that students would not have to compete for the few spots near a power source.\n\nQuestion: What is the main idea of this passage?","c":["The library made changes to better serve students who study late","The library plans to close earlier next year","Students prefer studying at home","The library is short of money"],"a":0,"e":"The passage describes extended hours and added outlets and lamps, all done to serve students who study late, which is the main idea.","d":3}];
QBANK["EI"] = [{"q":"What is the unit of electrical resistance?","c":["Volt","Ampere","Ohm","Watt"],"a":2,"e":"Resistance is measured in ohms. The volt measures voltage, the ampere measures current, and the watt measures power.","d":1},{"q":"According to Ohm's law, what voltage is required to push 2 amps through a 10-ohm resistor?","c":["5 V","12 V","20 V","0.2 V"],"a":2,"e":"V = I * R = 2 A * 10 ohms = 20 V.","d":2},{"q":"A 120-volt source drives a current through a 60-ohm resistor. What is the current?","c":["2 A","0.5 A","180 A","7200 A"],"a":0,"e":"I = V / R = 120 V / 60 ohms = 2 A.","d":2},{"q":"What is the total resistance of two 100-ohm resistors connected in series?","c":["50 ohms","100 ohms","150 ohms","200 ohms"],"a":3,"e":"In series, resistances add: 100 + 100 = 200 ohms.","d":2},{"q":"What is the total resistance of two 100-ohm resistors connected in parallel?","c":["50 ohms","100 ohms","150 ohms","200 ohms"],"a":0,"e":"For two equal parallel resistors, total = R/2 = 100/2 = 50 ohms.","d":2},{"q":"How much power is dissipated by a device that draws 3 amps at 12 volts?","c":["4 W","15 W","36 W","9 W"],"a":2,"e":"P = V * I = 12 V * 3 A = 36 W.","d":2},{"q":"Which of the following is the best electrical conductor?","c":["Rubber","Copper","Glass","Plastic"],"a":1,"e":"Copper is an excellent conductor and is widely used in wiring. Rubber, glass, and plastic are insulators.","d":1},{"q":"Which material is commonly used as an electrical insulator?","c":["Silver","Aluminum","Rubber","Gold"],"a":2,"e":"Rubber is an insulator that resists current flow. Silver, aluminum, and gold are good conductors.","d":1},{"q":"What does AC stand for in electricity?","c":["Active Current","Alternating Current","Ampere Charge","Applied Capacitance"],"a":1,"e":"AC stands for alternating current, in which the direction of current flow periodically reverses.","d":1},{"q":"In a DC circuit, the current flows in which manner?","c":["In one constant direction","Reversing 60 times per second","Only through capacitors","In a circular magnetic loop"],"a":0,"e":"DC (direct current) flows in one constant direction, such as from a battery.","d":1},{"q":"What is the unit of frequency?","c":["Farad","Henry","Hertz","Joule"],"a":2,"e":"Frequency is measured in hertz (Hz), which equals cycles per second.","d":1},{"q":"Standard household AC power in the United States has a frequency of:","c":["50 Hz","60 Hz","120 Hz","240 Hz"],"a":1,"e":"U.S. household AC is delivered at 60 Hz (60 cycles per second).","d":1},{"q":"Which component stores energy in an electric field and opposes changes in voltage?","c":["Resistor","Capacitor","Inductor","Diode"],"a":1,"e":"A capacitor stores energy in an electric field between its plates and opposes sudden voltage changes.","d":2},{"q":"Which component allows current to flow in only one direction?","c":["Resistor","Capacitor","Diode","Inductor"],"a":2,"e":"A diode permits current to flow in one direction and blocks it in the reverse direction.","d":1},{"q":"What is the unit of capacitance?","c":["Henry","Farad","Ohm","Hertz"],"a":1,"e":"Capacitance is measured in farads (F).","d":1},{"q":"An inductor stores energy in what form?","c":["Electric field","Chemical bonds","Magnetic field","Heat"],"a":2,"e":"An inductor (coil) stores energy in the magnetic field created by current flowing through it.","d":2},{"q":"A transformer is used primarily to:","c":["Store electrical charge","Convert AC voltage from one level to another","Rectify AC into DC","Amplify a signal"],"a":1,"e":"A transformer changes AC voltage levels (step up or step down) using electromagnetic induction between coils.","d":2},{"q":"A step-up transformer has:","c":["More turns on the secondary than the primary","More turns on the primary than the secondary","Equal turns on both windings","No primary winding"],"a":0,"e":"A step-up transformer has more turns on the secondary coil, increasing the output voltage.","d":2},{"q":"Which device is commonly used to amplify electrical signals or act as a switch?","c":["Resistor","Capacitor","Transistor","Fuse"],"a":2,"e":"A transistor can amplify signals or switch current, and is a fundamental building block of electronics.","d":1},{"q":"What is the total voltage of three 1.5-volt batteries connected in series?","c":["1.5 V","3 V","4.5 V","0.5 V"],"a":2,"e":"Series cells add their voltages: 1.5 + 1.5 + 1.5 = 4.5 V.","d":2},{"q":"In a series circuit, the current is:","c":["Different in each component","The same through all components","Zero everywhere","Highest at the source only"],"a":1,"e":"In a series circuit there is only one path, so the same current flows through every component.","d":1},{"q":"In a parallel circuit, the voltage across each branch is:","c":["The same across all branches","Divided equally among branches","Zero","Always increasing"],"a":0,"e":"Branches in parallel share the same two nodes, so each branch has the same voltage.","d":2},{"q":"How much current flows through a 240-ohm resistor connected across a 12-volt battery?","c":["0.05 A","2 A","20 A","0.5 A"],"a":0,"e":"I = V / R = 12 V / 240 ohms = 0.05 A.","d":2},{"q":"A semiconductor's conductivity is:","c":["Always zero","Greater than a metal's","Between that of a conductor and an insulator","Infinite"],"a":2,"e":"Semiconductors such as silicon conduct better than insulators but worse than conductors, and their conductivity can be controlled.","d":2},{"q":"What is the purpose of grounding an electrical system?","c":["To increase voltage","To provide a safe path for fault current","To store extra charge","To raise the frequency"],"a":1,"e":"Grounding provides a low-resistance safe path for fault current to flow to earth, protecting people and equipment.","d":2},{"q":"The unit of electric current is the:","c":["Volt","Ohm","Ampere","Coulomb"],"a":2,"e":"Current is measured in amperes (amps). The coulomb measures charge, not current rate.","d":1},{"q":"What is the power dissipated by a 4-ohm resistor carrying 3 amps?","c":["12 W","36 W","7 W","48 W"],"a":1,"e":"P = I^2 * R = 3^2 * 4 = 9 * 4 = 36 W.","d":3},{"q":"Which color band on a resistor represents the digit 0 in the standard color code?","c":["Brown","Black","Red","Gold"],"a":1,"e":"In the resistor color code, black = 0, brown = 1, red = 2.","d":2},{"q":"A fuse protects a circuit by:","c":["Increasing the current","Melting and opening the circuit during overcurrent","Storing excess voltage","Converting AC to DC"],"a":1,"e":"A fuse contains a thin wire that melts when current exceeds its rating, breaking the circuit to prevent damage.","d":1},{"q":"What happens to total resistance when more resistors are added in parallel?","c":["It increases","It decreases","It stays the same","It becomes infinite"],"a":1,"e":"Adding parallel paths gives current more routes, so total resistance decreases below the smallest resistor.","d":2},{"q":"The resistance of two 6-ohm resistors in parallel is:","c":["3 ohms","6 ohms","12 ohms","2 ohms"],"a":0,"e":"For two equal parallel resistors, total = R/2 = 6/2 = 3 ohms.","d":2},{"q":"A material through which electric current flows easily is called a:","c":["Insulator","Conductor","Dielectric","Resistor"],"a":1,"e":"A conductor allows electric current to flow easily because it has many free electrons.","d":1},{"q":"What voltage is across a 5-ohm resistor that dissipates 80 watts of power?","c":["16 V","20 V","400 V","4 V"],"a":1,"e":"P = V^2 / R, so V = sqrt(P * R) = sqrt(80 * 5) = sqrt(400) = 20 V.","d":3},{"q":"Around a wire carrying current, what is created?","c":["An electric charge only","A magnetic field","A vacuum","Static electricity only"],"a":1,"e":"A current-carrying conductor produces a magnetic field around it; this is the basis of electromagnetism.","d":2},{"q":"What is 1 kilovolt equal to?","c":["10 volts","100 volts","1000 volts","0.001 volts"],"a":2,"e":"The prefix kilo means 1000, so 1 kilovolt = 1000 volts.","d":1},{"q":"The unit of electric power is the:","c":["Joule","Watt","Volt","Henry"],"a":1,"e":"Electric power is measured in watts (W). One watt equals one joule per second.","d":1},{"q":"What is the resistance of a circuit that draws 4 amps from a 24-volt source?","c":["6 ohms","96 ohms","0.17 ohms","20 ohms"],"a":0,"e":"R = V / I = 24 V / 4 A = 6 ohms.","d":2},{"q":"Three resistors of 2 ohms, 3 ohms, and 5 ohms are connected in series. What is the total resistance?","c":["10 ohms","3 ohms","0.97 ohms","30 ohms"],"a":0,"e":"In series, resistances add: 2 + 3 + 5 = 10 ohms.","d":2},{"q":"What is the total resistance of three 30-ohm resistors connected in parallel?","c":["90 ohms","30 ohms","10 ohms","15 ohms"],"a":2,"e":"For equal parallel resistors, total = R / n = 30 / 3 = 10 ohms.","d":3},{"q":"A transformer has 200 turns on the primary and 50 turns on the secondary. If the primary voltage is 240 V, what is the secondary voltage?","c":["960 V","60 V","48 V","120 V"],"a":1,"e":"Vs = Vp * (Ns / Np) = 240 * (50 / 200) = 240 * 0.25 = 60 V. This is a step-down transformer.","d":3},{"q":"A 10-ohm and a 15-ohm resistor are connected in series across a 25-volt source. What current flows?","c":["1 A","2.5 A","0.4 A","25 A"],"a":0,"e":"Total R = 10 + 15 = 25 ohms; I = V / R = 25 V / 25 ohms = 1 A.","d":3},{"q":"How much power does a 6-ohm resistor dissipate when 12 volts is applied across it?","c":["2 W","72 W","24 W","0.5 W"],"a":2,"e":"P = V^2 / R = 12^2 / 6 = 144 / 6 = 24 W.","d":3},{"q":"What is the period of an AC signal with a frequency of 50 Hz?","c":["50 seconds","0.02 seconds","2 seconds","0.5 seconds"],"a":1,"e":"Period T = 1 / f = 1 / 50 = 0.02 seconds (20 milliseconds).","d":3},{"q":"The unit of inductance is the:","c":["Farad","Henry","Tesla","Ohm"],"a":1,"e":"Inductance is measured in henries (H). The farad is for capacitance and the tesla is for magnetic flux density.","d":1},{"q":"What device converts AC into DC?","c":["Transformer","Rectifier","Oscillator","Capacitor"],"a":1,"e":"A rectifier, typically built from diodes, converts alternating current into direct current.","d":2},{"q":"A transformer steps 120 V down to 24 V. If the primary has 500 turns, how many turns does the secondary have?","c":["2500 turns","100 turns","250 turns","600 turns"],"a":1,"e":"Ns = Np * (Vs / Vp) = 500 * (24 / 120) = 500 * 0.2 = 100 turns.","d":3},{"q":"When you double the voltage across a fixed resistor, the power dissipated:","c":["Doubles","Halves","Quadruples","Stays the same"],"a":2,"e":"Since P = V^2 / R, doubling V multiplies power by 2^2 = 4, so the power quadruples.","d":3},{"q":"A 100-ohm and a 100-ohm resistor are in parallel, and that combination is in series with a 50-ohm resistor. What is the total resistance?","c":["250 ohms","100 ohms","75 ohms","150 ohms"],"a":1,"e":"Parallel pair = 100/2 = 50 ohms; in series with 50 ohms gives 50 + 50 = 100 ohms.","d":3},{"q":"A 12-volt battery delivers 5 amps to a load. How much power is the load using?","c":["2.4 W","17 W","60 W","7 W"],"a":2,"e":"P = V * I = 12 V * 5 A = 60 W.","d":2},{"q":"Like magnetic poles do what to each other?","c":["Repel","Attract","Cancel charge","Generate current"],"a":0,"e":"Like magnetic poles (north-north or south-south) repel, while opposite poles attract.","d":1}];
QBANK["GS"] = [{"q":"Which organelle is known as the powerhouse of the cell because it produces most of the cell's ATP?","c":["Mitochondrion","Ribosome","Golgi apparatus","Lysosome"],"a":0,"e":"Mitochondria carry out cellular respiration, generating most of the cell's ATP energy.","d":1},{"q":"In humans, which type of blood cell is primarily responsible for fighting infection?","c":["Red blood cells","White blood cells","Platelets","Plasma cells only"],"a":1,"e":"White blood cells (leukocytes) are the main components of the immune system that fight infection.","d":1},{"q":"What is the basic structural and functional unit of all living organisms?","c":["The atom","The tissue","The organ","The cell"],"a":3,"e":"The cell is the smallest unit that can carry out all life processes; all organisms are made of cells.","d":1},{"q":"Which process do green plants use to convert sunlight, water, and carbon dioxide into glucose?","c":["Respiration","Photosynthesis","Fermentation","Transpiration"],"a":1,"e":"Photosynthesis uses light energy to convert CO2 and water into glucose and oxygen.","d":1},{"q":"Genetic information in cells is primarily stored in molecules of:","c":["DNA","ATP","RNA polymerase","Glucose"],"a":0,"e":"DNA (deoxyribonucleic acid) carries the hereditary instructions in the form of genes.","d":1},{"q":"Which organ system is primarily responsible for pumping blood throughout the body?","c":["Respiratory system","Circulatory system","Digestive system","Nervous system"],"a":1,"e":"The circulatory (cardiovascular) system, centered on the heart, pumps blood through the body.","d":1},{"q":"An organism that makes its own food is called a:","c":["Consumer","Decomposer","Producer","Parasite"],"a":2,"e":"Producers, such as plants, make their own food through photosynthesis and form the base of food chains.","d":2},{"q":"In which part of the human body does most nutrient absorption occur?","c":["Stomach","Esophagus","Large intestine","Small intestine"],"a":3,"e":"The small intestine, with its large surface area of villi, absorbs most digested nutrients.","d":2},{"q":"A trait controlled by an allele that is expressed only when two copies are present is called:","c":["Dominant","Recessive","Codominant","Mutant"],"a":1,"e":"A recessive trait is masked by a dominant allele and appears only when both alleles are recessive.","d":2},{"q":"Which of the following is the correct order, from smallest to largest, of biological organization?","c":["Organ, tissue, cell, organism","Tissue, cell, organism, organ","Cell, tissue, organ, organism","Cell, organ, tissue, organism"],"a":2,"e":"Cells form tissues, tissues form organs, and organs work together in an organism.","d":2},{"q":"The gas that humans inhale and that is essential for cellular respiration is:","c":["Carbon dioxide","Oxygen","Nitrogen","Helium"],"a":1,"e":"Oxygen is taken in during breathing and used by cells to release energy in respiration.","d":1},{"q":"Which kingdom includes organisms such as mushrooms, molds, and yeasts?","c":["Plantae","Animalia","Protista","Fungi"],"a":3,"e":"Fungi are a separate kingdom of organisms that absorb nutrients and include mushrooms, molds, and yeasts.","d":2},{"q":"What is the chemical symbol for sodium?","c":["So","Na","Sd","S"],"a":1,"e":"Sodium's symbol Na comes from its Latin name natrium.","d":2},{"q":"The smallest particle of an element that retains the properties of that element is the:","c":["Atom","Molecule","Electron","Proton"],"a":0,"e":"An atom is the smallest unit of an element that still has that element's chemical properties.","d":1},{"q":"Which subatomic particle carries a negative electric charge?","c":["Proton","Neutron","Electron","Nucleus"],"a":2,"e":"Electrons carry a negative charge; protons are positive and neutrons are neutral.","d":1},{"q":"On the pH scale, a solution with a pH of 3 is considered:","c":["Strongly basic","Neutral","Acidic","Pure water"],"a":2,"e":"A pH below 7 is acidic; pH 7 is neutral and above 7 is basic.","d":2},{"q":"What is the chemical formula for water?","c":["CO2","H2O","O2","NaCl"],"a":1,"e":"Water is made of two hydrogen atoms and one oxygen atom, giving the formula H2O.","d":1},{"q":"When a substance changes directly from a solid to a gas without becoming a liquid, the process is called:","c":["Condensation","Evaporation","Melting","Sublimation"],"a":3,"e":"Sublimation is the phase change from solid directly to gas, as seen with dry ice.","d":2},{"q":"In the periodic table, elements in the same vertical column are called a:","c":["Period","Series","Group","Shell"],"a":2,"e":"A group (or family) is a vertical column of elements that share similar chemical properties.","d":2},{"q":"Which of the following is a chemical change rather than a physical change?","c":["Melting ice","Rusting iron","Boiling water","Crushing a can"],"a":1,"e":"Rusting forms a new substance (iron oxide), making it a chemical change; the others are physical.","d":2},{"q":"Table salt is a compound formed from sodium and which other element?","c":["Carbon","Calcium","Potassium","Chlorine"],"a":3,"e":"Table salt is sodium chloride (NaCl), composed of sodium and chlorine.","d":1},{"q":"The number of protons in the nucleus of an atom is called its:","c":["Atomic number","Mass number","Valence number","Isotope number"],"a":0,"e":"The atomic number equals the number of protons and identifies the element.","d":2},{"q":"Which state of matter has a definite volume but takes the shape of its container?","c":["Solid","Gas","Liquid","Plasma"],"a":2,"e":"Liquids keep a fixed volume but flow to take the shape of whatever holds them.","d":2},{"q":"In a chemical equation, the substances that react together are called the:","c":["Products","Reactants","Catalysts","Solvents"],"a":1,"e":"Reactants are the starting substances; products are what is formed by the reaction.","d":2},{"q":"A substance that speeds up a chemical reaction without being used up is a:","c":["Catalyst","Solute","Reactant","Precipitate"],"a":0,"e":"A catalyst increases reaction rate and is not consumed in the reaction.","d":2},{"q":"According to Newton's first law of motion, an object in motion will:","c":["Stay in motion unless acted on by a force","Slow down and stop on its own","Speed up without any force","Always move in a circle"],"a":0,"e":"Newton's first law (inertia) states an object keeps its motion unless an outside force acts on it.","d":2},{"q":"The unit used to measure force in the SI system is the:","c":["Joule","Watt","Newton","Pascal"],"a":2,"e":"Force is measured in newtons (N); a joule is energy and a watt is power.","d":2},{"q":"Energy stored in an object because of its position or height is called:","c":["Kinetic energy","Potential energy","Thermal energy","Electrical energy"],"a":1,"e":"Potential energy is stored energy due to position, such as a raised object's gravitational potential energy.","d":1},{"q":"Which of these is an example of a simple machine?","c":["A lever","A car engine","A computer","A battery"],"a":0,"e":"A lever is one of the six classic simple machines used to change force or motion.","d":1},{"q":"In physics, work is done when:","c":["An object is held still","An object stays at rest","A force is applied with no movement","A force moves an object a distance"],"a":3,"e":"Work equals force times distance; no work is done if there is no movement in the force's direction.","d":2},{"q":"The speed of light in a vacuum is approximately:","c":["300 kilometers per second","3,000 meters per second","300,000 kilometers per second","30 meters per second"],"a":2,"e":"Light travels at about 300,000 km/s (3 x 10^8 meters per second) in a vacuum.","d":2},{"q":"What happens to the boiling point of water as altitude increases?","c":["It stays the same","It increases","It decreases","It becomes zero"],"a":2,"e":"Lower air pressure at high altitude lets water boil at a lower temperature.","d":2},{"q":"Which of the following best describes acceleration?","c":["The total distance traveled","The rate of change of velocity","A constant speed","The force of gravity"],"a":1,"e":"Acceleration is how quickly velocity changes over time, including changes in speed or direction.","d":2},{"q":"In an electric circuit, the unit of electrical resistance is the:","c":["Volt","Ohm","Ampere","Watt"],"a":1,"e":"Resistance is measured in ohms; volts measure voltage and amperes measure current.","d":2},{"q":"Sound travels fastest through which of the following?","c":["A vacuum","Air","Water","Steel"],"a":3,"e":"Sound moves fastest through dense solids like steel and cannot travel through a vacuum.","d":2},{"q":"Newton's third law of motion states that for every action there is:","c":["No reaction","A larger reaction","An equal and opposite reaction","A delayed reaction"],"a":2,"e":"Newton's third law says forces come in pairs that are equal in size and opposite in direction.","d":1},{"q":"Which color of visible light has the longest wavelength?","c":["Blue","Green","Violet","Red"],"a":3,"e":"Red light has the longest wavelength of visible light; violet has the shortest.","d":2},{"q":"Which planet is closest to the Sun?","c":["Mercury","Venus","Earth","Mars"],"a":0,"e":"Mercury is the innermost planet, orbiting closest to the Sun.","d":1},{"q":"The process by which water vapor in the air turns into liquid water is called:","c":["Evaporation","Condensation","Precipitation","Sublimation"],"a":1,"e":"Condensation is the change of water vapor to liquid, as when clouds or dew form.","d":1},{"q":"The outermost layer of the Earth, on which we live, is called the:","c":["Mantle","Outer core","Crust","Inner core"],"a":2,"e":"The crust is the thin, solid outermost layer of the Earth above the mantle.","d":1},{"q":"Igneous rock is formed by the:","c":["Cementing of sediment","Heat and pressure on existing rock","Erosion of mountains","Cooling and hardening of magma or lava"],"a":3,"e":"Igneous rock forms when molten magma or lava cools and solidifies.","d":2},{"q":"Which layer of the atmosphere contains the ozone layer and is where most weather occurs below it?","c":["Stratosphere","Mesosphere","Thermosphere","Exosphere"],"a":0,"e":"The stratosphere holds the ozone layer; the troposphere below it is where most weather occurs.","d":2},{"q":"Approximately what percentage of the Earth's surface is covered by water?","c":["About 30 percent","About 70 percent","About 50 percent","About 90 percent"],"a":1,"e":"Water covers roughly 70 percent of Earth's surface, mostly in the oceans.","d":1},{"q":"What causes the regular rise and fall of ocean tides?","c":["Wind patterns","The gravitational pull of the Moon and Sun","Underwater volcanoes","Changes in water temperature"],"a":1,"e":"Tides are caused mainly by the Moon's gravity, with the Sun also contributing.","d":2},{"q":"A scientist who studies the weather and atmosphere is called a:","c":["Geologist","Astronomer","Seismologist","Meteorologist"],"a":3,"e":"Meteorologists study weather and atmospheric conditions; geologists study rocks and astronomers study space.","d":1},{"q":"During mitosis, a single cell divides to produce two daughter cells that are:","c":["Genetically identical to the parent","Genetically different from the parent","Half the chromosome number","Always reproductive cells"],"a":0,"e":"Mitosis produces two daughter cells genetically identical to the parent cell, each with the full chromosome number.","d":3},{"q":"The exchange of oxygen and carbon dioxide in the lungs takes place in tiny air sacs called:","c":["Bronchi","Alveoli","Capillaries","Cilia"],"a":1,"e":"Alveoli are the small air sacs in the lungs where gas exchange with the blood occurs.","d":3},{"q":"In genetics, an organism's observable physical traits make up its:","c":["Genotype","Phenotype","Allele","Genome"],"a":1,"e":"The phenotype is the set of observable characteristics, while the genotype is the genetic makeup.","d":3},{"q":"The process by which organisms best suited to their environment tend to survive and reproduce is called:","c":["Natural selection","Mutation","Migration","Photosynthesis"],"a":0,"e":"Natural selection, described by Darwin, is the differential survival and reproduction of organisms based on traits.","d":2},{"q":"The reaction of an acid with a base to produce a salt and water is called:","c":["Oxidation","Neutralization","Combustion","Fermentation"],"a":1,"e":"Neutralization is the reaction between an acid and a base that yields a salt and water.","d":3},{"q":"The horizontal rows of the periodic table are called:","c":["Groups","Families","Periods","Columns"],"a":2,"e":"Periods are the horizontal rows; the number of the period equals the number of electron shells.","d":3},{"q":"Which gas makes up the largest percentage of Earth's atmosphere?","c":["Oxygen","Nitrogen","Carbon dioxide","Argon"],"a":1,"e":"Nitrogen makes up about 78 percent of the atmosphere, while oxygen is about 21 percent.","d":2},{"q":"The bonding in which atoms share pairs of electrons is called:","c":["Ionic bonding","Covalent bonding","Metallic bonding","Hydrogen bonding"],"a":1,"e":"In covalent bonds atoms share electron pairs; in ionic bonds electrons are transferred.","d":3},{"q":"The transfer of heat through direct contact between materials is called:","c":["Radiation","Convection","Conduction","Insulation"],"a":2,"e":"Conduction transfers heat through direct contact; convection uses fluid movement and radiation uses waves.","d":3},{"q":"The bending of light as it passes from one medium into another is called:","c":["Reflection","Refraction","Diffraction","Absorption"],"a":1,"e":"Refraction is the bending of light when it changes speed moving between media, as in a lens or prism.","d":3},{"q":"The number of wave cycles that pass a point each second is the wave's:","c":["Amplitude","Wavelength","Frequency","Velocity"],"a":2,"e":"Frequency is the number of cycles per second, measured in hertz.","d":3},{"q":"Doubling the mass of an object while applying the same force will cause its acceleration to:","c":["Double","Stay the same","Be cut in half","Quadruple"],"a":2,"e":"By Newton's second law, acceleration equals force divided by mass, so doubling mass halves acceleration.","d":3},{"q":"A device that transforms mechanical energy into electrical energy is a:","c":["Motor","Generator","Transformer","Resistor"],"a":1,"e":"A generator converts mechanical energy into electrical energy; a motor does the reverse.","d":3},{"q":"Which planet in our solar system is known as the Red Planet?","c":["Jupiter","Venus","Mars","Saturn"],"a":2,"e":"Mars appears red because of iron oxide (rust) on its surface.","d":1},{"q":"A sudden shaking of the ground caused by movement of Earth's tectonic plates is a(n):","c":["Tsunami","Earthquake","Hurricane","Avalanche"],"a":1,"e":"Earthquakes result from the sudden release of energy as tectonic plates shift along faults.","d":2},{"q":"The instrument used to measure the magnitude of earthquakes records data as a:","c":["Barometer reading","Seismogram","Thermogram","Spectrum"],"a":1,"e":"A seismograph records ground motion as a seismogram, used to determine earthquake magnitude.","d":3},{"q":"Sedimentary rock is most often formed by the:","c":["Cooling of lava","Compaction and cementing of sediments","Melting of minerals","Cooling of magma underground"],"a":1,"e":"Sedimentary rock forms as layers of sediment are compacted and cemented over time.","d":3},{"q":"Which of the following best explains why we experience seasons on Earth?","c":["The changing distance between Earth and the Sun","The tilt of Earth's axis as it orbits the Sun","The rotation of Earth on its axis each day","Variations in the Sun's energy output"],"a":1,"e":"Seasons are caused by the roughly 23.5 degree tilt of Earth's axis, changing sunlight angle through the year.","d":3},{"q":"The dark, relatively cool regions sometimes seen on the surface of the Sun are called:","c":["Solar flares","Sunspots","Coronas","Eclipses"],"a":1,"e":"Sunspots are cooler, darker areas on the Sun caused by intense magnetic activity.","d":3},{"q":"Half of the genetic material carried by a sperm or egg cell results from a special type of division called:","c":["Mitosis","Meiosis","Binary fission","Replication"],"a":1,"e":"Meiosis produces gametes (sperm and egg) with half the chromosome number of body cells.","d":3}];
QBANK["MC"] = [{"q":"A lever has its fulcrum 2 ft from a 100 lb load and 8 ft from the point where effort is applied. How much effort is needed to balance the load?","c":["25 lb","50 lb","100 lb","400 lb"],"a":0,"e":"For a balanced lever, load x load-arm = effort x effort-arm. So 100 lb x 2 ft = effort x 8 ft, giving effort = 200/8 = 25 lb.","d":3},{"q":"What is the mechanical advantage of a machine that uses 20 lb of effort to lift a 100 lb load?","c":["2","5","20","80"],"a":1,"e":"Mechanical advantage = output force / input force = 100 lb / 20 lb = 5.","d":2},{"q":"How much work is done lifting a 50 lb box straight up a height of 4 ft?","c":["12.5 ft-lb","54 ft-lb","200 ft-lb","2000 ft-lb"],"a":2,"e":"Work = force x distance = 50 lb x 4 ft = 200 ft-lb.","d":2},{"q":"A single fixed pulley is used to lift a load. What is its main advantage?","c":["It doubles the force applied","It changes the direction of the force","It halves the distance the rope must move","It eliminates friction"],"a":1,"e":"A single fixed pulley has a mechanical advantage of 1; it does not multiply force but changes the direction of the applied force, letting you pull down to lift up.","d":1},{"q":"Two gears mesh together. The driver gear has 10 teeth and the driven gear has 30 teeth. If the driver turns at 60 rpm, how fast does the driven gear turn?","c":["180 rpm","60 rpm","30 rpm","20 rpm"],"a":3,"e":"Gear speeds are inversely proportional to teeth. Driven speed = driver speed x (driver teeth / driven teeth) = 60 x (10/30) = 20 rpm.","d":3},{"q":"Pressure is defined as:","c":["Force multiplied by area","Force divided by area","Force multiplied by distance","Mass divided by volume"],"a":1,"e":"Pressure = force / area. A given force spread over a smaller area produces greater pressure.","d":1},{"q":"A hydraulic system has a small piston of area 2 sq in and a large piston of area 10 sq in. A force of 50 lb is applied to the small piston. What force is produced at the large piston?","c":["10 lb","50 lb","250 lb","500 lb"],"a":2,"e":"By Pascal's principle pressure is equal: F1/A1 = F2/A2. So F2 = 50 lb x (10/2) = 250 lb.","d":3},{"q":"An inclined plane is 12 ft long and rises 3 ft. What is its ideal mechanical advantage?","c":["4","3","9","36"],"a":0,"e":"For an inclined plane, IMA = length of slope / height = 12 ft / 3 ft = 4.","d":2},{"q":"Which simple machine is essentially an inclined plane wrapped around a cylinder?","c":["Wedge","Pulley","Screw","Lever"],"a":2,"e":"A screw is an inclined plane wrapped around a central shaft; the threads form the spiral ramp.","d":1},{"q":"A wheelbarrow is an example of which class of lever?","c":["First-class","Second-class","Third-class","Fourth-class"],"a":1,"e":"In a wheelbarrow the load is between the fulcrum (wheel) and the effort (handles), which defines a second-class lever.","d":1},{"q":"Torque is best described as:","c":["A pushing force in a straight line","The turning effect of a force about a pivot","The energy stored in a spring","The resistance to sliding motion"],"a":1,"e":"Torque is the rotational or turning effect of a force, equal to force times the perpendicular distance from the pivot (torque = force x lever arm).","d":1},{"q":"A force of 30 lb is applied at the end of a wrench 2 ft long, perpendicular to the handle. What torque is produced about the bolt?","c":["15 ft-lb","32 ft-lb","60 ft-lb","120 ft-lb"],"a":2,"e":"Torque = force x lever arm = 30 lb x 2 ft = 60 ft-lb.","d":2},{"q":"Which type of friction is generally greatest for the same surfaces?","c":["Rolling friction","Kinetic (sliding) friction","Static friction","Fluid friction"],"a":2,"e":"Static friction (which must be overcome to start motion) is typically greater than kinetic friction, and rolling friction is usually the smallest.","d":2},{"q":"A block-and-tackle system supports a load with 4 strands of rope. What is its ideal mechanical advantage?","c":["1","2","4","8"],"a":2,"e":"The ideal mechanical advantage of a pulley system equals the number of rope strands supporting the load, here 4.","d":2},{"q":"Which of the following has the most potential energy?","c":["A 10 lb weight resting on the ground","A 10 lb weight held 5 ft above the ground","A 10 lb weight held 2 ft above the ground","A 10 lb weight sliding on the floor"],"a":1,"e":"Gravitational potential energy = weight x height. The greatest height (5 ft) gives the most potential energy.","d":1},{"q":"Water is densest and exerts the greatest pressure at which point in a tank?","c":["At the surface","Halfway down","At the bottom","Pressure is equal everywhere"],"a":2,"e":"Liquid pressure increases with depth because of the weight of the water above, so it is greatest at the bottom.","d":1},{"q":"A 200 lb load is lifted using a machine with a mechanical advantage of 4. Ignoring friction, how much effort force is required?","c":["50 lb","100 lb","200 lb","800 lb"],"a":0,"e":"MA = load / effort, so effort = load / MA = 200 lb / 4 = 50 lb.","d":2},{"q":"Two children sit on a seesaw. A 60 lb child sits 4 ft from the pivot. How far from the pivot must a 40 lb child sit to balance it?","c":["3 ft","4 ft","6 ft","8 ft"],"a":2,"e":"Balance requires equal torques: 60 lb x 4 ft = 40 lb x d, so d = 240/40 = 6 ft.","d":3},{"q":"As a moving object's speed increases, its kinetic energy:","c":["Decreases","Stays the same","Increases","Becomes zero"],"a":2,"e":"Kinetic energy = 1/2 x mass x velocity squared. Increasing speed increases kinetic energy (and it rises with the square of velocity).","d":1},{"q":"Which arrangement of a board ramp makes it easiest to push a heavy barrel up to a fixed height?","c":["A shorter, steeper ramp","A longer, more gradual ramp","Both require the same effort","A vertical lift"],"a":1,"e":"A longer ramp increases the mechanical advantage (slope length / height), reducing the effort force needed, though over a longer distance.","d":2},{"q":"A spring stretches 2 in when a 10 lb weight hangs from it. How far will it stretch with a 25 lb weight, assuming it obeys Hooke's law?","c":["2 in","4 in","5 in","10 in"],"a":2,"e":"Hooke's law: stretch is proportional to force. The spring stretches 0.2 in per lb (2 in / 10 lb), so 25 lb x 0.2 = 5 in.","d":3},{"q":"Momentum of a moving object is calculated as:","c":["Mass divided by velocity","Mass times velocity","Mass times acceleration","Force times time squared"],"a":1,"e":"Momentum = mass x velocity. A heavier or faster object has more momentum.","d":1},{"q":"A wheel-and-axle has a wheel radius of 12 in and an axle radius of 3 in. What is its ideal mechanical advantage?","c":["3","4","9","36"],"a":1,"e":"For a wheel and axle, IMA = wheel radius / axle radius = 12 / 3 = 4.","d":2},{"q":"In a first-class lever, the fulcrum is located:","c":["Between the effort and the load","At the same point as the load","Beyond the effort","Between two loads"],"a":0,"e":"A first-class lever (like a seesaw or pliers) has the fulcrum positioned between the effort and the load.","d":1},{"q":"If you press a thumbtack, the sharp point pushes into the wood more easily than the flat head pushes into your thumb because:","c":["The point has a larger area","The point concentrates the force over a smaller area","The head receives more force","Wood is softer than skin"],"a":1,"e":"Pressure = force / area. The small point area produces very high pressure from the same force, while the wide head spreads force over a large area.","d":2},{"q":"A 100 lb crate is dragged 10 ft across a floor against a friction force of 30 lb. How much work is done against friction?","c":["70 ft-lb","130 ft-lb","300 ft-lb","1000 ft-lb"],"a":2,"e":"Work against friction = friction force x distance = 30 lb x 10 ft = 300 ft-lb.","d":2},{"q":"Which statement about a machine's mechanical advantage and the distance traveled is true?","c":["Greater force output requires greater input distance","Greater force output requires shorter input distance","Force and distance are unrelated in machines","Machines create energy to gain force"],"a":0,"e":"Machines trade force for distance; to multiply force you must apply the effort over a greater distance, since work in equals work out (ignoring friction).","d":2},{"q":"Two gears are meshed. The driver gear turns clockwise. The single gear directly meshed with it turns:","c":["Clockwise","Counterclockwise","It does not turn","In random directions"],"a":1,"e":"Directly meshed gears rotate in opposite directions, so a clockwise driver turns the meshed gear counterclockwise.","d":1},{"q":"An object floats in water when:","c":["Its weight is greater than the buoyant force","Its weight equals the buoyant force","It has no mass","It is heavier than water of equal volume"],"a":1,"e":"An object floats when the upward buoyant force equals its weight; this happens when it is less dense than the fluid, displacing enough fluid to support it.","d":2},{"q":"A 3 lb object and a 6 lb object are dropped from the same height in a vacuum. Which hits the ground first?","c":["The 3 lb object","The 6 lb object","They hit at the same time","Neither falls in a vacuum"],"a":2,"e":"In a vacuum there is no air resistance, so all objects fall with the same acceleration due to gravity and reach the ground at the same time.","d":1},{"q":"Increasing the diameter of a hydraulic output piston (while keeping the input the same) will:","c":["Decrease the output force","Increase the output force","Have no effect on force","Reduce the system pressure"],"a":1,"e":"Output force = pressure x area. A larger output piston has more area, so for the same pressure it produces a greater output force.","d":2},{"q":"A pendulum swings back and forth. At the lowest point of its swing, it has the most:","c":["Potential energy","Kinetic energy","Friction","Mass"],"a":1,"e":"At the lowest point the pendulum moves fastest, so kinetic energy is greatest and potential energy is least; energy converts between the two.","d":2},{"q":"A nutcracker uses two handles joined at a hinge to crack a nut placed near the hinge. This is an example of:","c":["A third-class lever","A second-class lever","A wheel and axle","A pulley"],"a":1,"e":"With the hinge as the fulcrum and the nut (load) between the fulcrum and the hand effort, the nutcracker acts as a second-class lever, multiplying force.","d":2},{"q":"Which change would increase the friction between two surfaces?","c":["Adding oil between them","Polishing both surfaces smooth","Pressing the surfaces together harder","Adding rollers underneath"],"a":2,"e":"Friction increases with the normal force pressing the surfaces together; pressing harder increases friction. Lubricants and smoothing reduce it.","d":1},{"q":"A gear with 40 teeth drives a gear with 8 teeth. What is the gear ratio of driver to driven, and does the small gear turn faster or slower?","c":["5 to 1, faster","1 to 5, slower","5 to 1, slower","1 to 1, same speed"],"a":0,"e":"Gear ratio = driver teeth / driven teeth = 40/8 = 5 to 1. The smaller driven gear turns 5 times for each turn of the driver, so it turns faster.","d":3},{"q":"A first-class lever has an effort arm of 6 ft and a load arm of 2 ft. What is its ideal mechanical advantage?","c":["4","8","12","3"],"a":3,"e":"For a lever, IMA = effort arm / load arm = 6 ft / 2 ft = 3.","d":2},{"q":"A movable pulley alone (rope fixed at one end, you pull the other) gives what ideal mechanical advantage?","c":["1","2","3","4"],"a":1,"e":"A single movable pulley has two rope strands supporting the load, giving an ideal mechanical advantage of 2.","d":1},{"q":"A force of 40 lb is applied to a wrench but at an angle, so only the perpendicular component of 30 lb acts on a handle 1.5 ft long. What torque results?","c":["45 ft-lb","60 ft-lb","45 lb","20 ft-lb"],"a":0,"e":"Only the perpendicular force does turning work: torque = 30 lb x 1.5 ft = 45 ft-lb.","d":3},{"q":"A machine has an ideal mechanical advantage of 5 but an actual mechanical advantage of 4 due to friction. What is its efficiency?","c":["20 percent","80 percent","90 percent","125 percent"],"a":1,"e":"Efficiency = actual MA / ideal MA = 4/5 = 0.80, or 80 percent.","d":3},{"q":"What net force is needed to accelerate a 10 slug mass at 4 ft per second squared? (slug is the unit of mass in the lb-ft-second system)","c":["2.5 lb","14 lb","40 lb","400 lb"],"a":2,"e":"Newton's second law: force = mass x acceleration = 10 slug x 4 ft/s^2 = 40 lb.","d":3},{"q":"Doubling the speed of a moving car increases its kinetic energy by a factor of:","c":["2","3","4","8"],"a":2,"e":"Kinetic energy = 1/2 x mass x velocity squared. Doubling velocity multiplies the square term by 4, so kinetic energy becomes 4 times as large.","d":2},{"q":"A hydraulic press has input piston area 1 sq in and output piston area 50 sq in. To lift a 2000 lb car, how much input force is needed (ignoring friction)?","c":["20 lb","40 lb","100 lb","1000 lb"],"a":1,"e":"By Pascal's principle, F_in / A_in = F_out / A_out, so F_in = 2000 lb x (1/50) = 40 lb.","d":3},{"q":"Which of these best stores energy when compressed and releases it later?","c":["A rigid steel bar","A coiled spring","A block of lead","A solid concrete cube"],"a":1,"e":"A spring is an elastic element that stores energy when compressed or stretched and releases it as it returns to its natural length.","d":1},{"q":"A 20 lb force compresses a spring with a spring constant of 5 lb per inch. How far does it compress?","c":["15 in","25 in","100 in","4 in"],"a":3,"e":"Hooke's law: force = k x distance, so distance = force / k = 20 lb / 5 lb-per-in = 4 in.","d":2},{"q":"Three pulleys are arranged so that 6 strands of rope support the load. To lift a 600 lb load ideally, what effort is needed?","c":["100 lb","200 lb","600 lb","3600 lb"],"a":0,"e":"Ideal MA equals the number of supporting strands, 6. Effort = load / MA = 600 lb / 6 = 100 lb.","d":3},{"q":"Why does a wide snowshoe keep a person from sinking into snow?","c":["It reduces the person's weight","It spreads weight over a larger area, lowering pressure","It increases friction with the snow","It makes the person lighter than air"],"a":1,"e":"Pressure = force / area. A larger contact area spreads the same weight over more surface, lowering the pressure on the snow.","d":1},{"q":"A car engine produces 100 ft-lb of torque. If this turns a wheel through a gear that doubles torque, the output torque is:","c":["50 ft-lb","100 ft-lb","200 ft-lb","400 ft-lb"],"a":2,"e":"A gear set that doubles torque produces 2 x 100 ft-lb = 200 ft-lb (at half the rotational speed, since power is conserved).","d":2},{"q":"An object is in equilibrium when:","c":["It is always moving","The net force on it is zero","It has maximum kinetic energy","Gravity does not act on it"],"a":1,"e":"An object is in equilibrium when all forces balance and the net force is zero, so it stays at rest or moves at constant velocity.","d":1},{"q":"A beam is supported at both ends and a weight rests at its center. Each support carries what fraction of the weight?","c":["All of it on one end","Half on each support","One quarter on each","None of it"],"a":1,"e":"By symmetry a centered load is shared equally, so each of the two supports carries half the weight.","d":2},{"q":"A 500 lb beam rests on two supports A and B that are 10 ft apart. Its weight acts 2 ft from support A. How much load does support B carry?","c":["200 lb","300 lb","400 lb","100 lb"],"a":3,"e":"Take torques about A: B x 10 ft = 500 lb x 2 ft, so B = 1000/10 = 100 lb. (Support A carries the other 400 lb.)","d":3},{"q":"A compound gear train has a first ratio of 3 to 1 and a second ratio of 2 to 1, both reducing speed. What is the overall speed reduction?","c":["5 to 1","6 to 1","1 to 6","2 to 3"],"a":1,"e":"Gear ratios in a train multiply: 3 x 2 = 6, giving an overall reduction of 6 to 1.","d":3},{"q":"A 12 lb weight hangs from a rope over a single fixed pulley. To hold it still, you must pull with about:","c":["6 lb","12 lb","24 lb","0 lb"],"a":1,"e":"A fixed pulley only changes direction and has a mechanical advantage of 1, so you must pull with the full 12 lb to hold the weight.","d":2},{"q":"Which has greater momentum: a 2 lb ball moving at 30 ft per second or a 6 lb ball moving at 10 ft per second?","c":["The 2 lb ball","The 6 lb ball","Cannot be determined","They have equal momentum"],"a":3,"e":"Momentum = mass-equivalent x velocity. Both give 2 x 30 = 60 and 6 x 10 = 60 in the same units, so their momenta are equal.","d":3},{"q":"A wedge is used to split a log. A longer, thinner wedge compared to a short, thick one provides:","c":["Less mechanical advantage","Greater mechanical advantage","No mechanical advantage","Greater weight only"],"a":1,"e":"A wedge is a moving inclined plane; the longer and thinner it is (greater length-to-thickness ratio), the greater its mechanical advantage.","d":2},{"q":"A 60 lb force is applied to the rim of a 2 ft radius wheel to turn an axle of 0.5 ft radius. What force is delivered at the axle (ideal)?","c":["15 lb","120 lb","240 lb","480 lb"],"a":2,"e":"Wheel-and-axle IMA = wheel radius / axle radius = 2 / 0.5 = 4. Output force = 60 lb x 4 = 240 lb.","d":3}];
